	function __construct($dash, $ajax = false, $loadFilter = 1){
		global $CONN, $IS_DOWNSTREAM;

		// check session
		if (session_status() == PHP_SESSION_NONE) session_start();
		$this->parentProjectId = (isset($_SESSION['is_Parent']) && ($_SESSION['is_Parent'] != "isParent")) ? $_SESSION['parent_project_id'] : $_SESSION['projectID'];

		if (!isset($_SESSION['projectID']) && !isset($_SESSION['appsLinks'])) die("Session Error! Please Refresh");

    	$appListsEncode = json_decode($_SESSION['appsLinks']);
	    if($appListsEncode->constructPackage_name){
			$packageInfoArr = explode('::', $appListsEncode->constructPackage_name);
			$this->jogetConstructApp = $packageInfoArr[0];
		}

		if($appListsEncode->documentPackage_name){
			$packageDocInfoArr = explode('::', $appListsEncode->documentPackage_name);
			$this->jogetDocApp = $packageDocInfoArr[0];
		}
    	
		if($appListsEncode->financePackage_name){
			$packageFinInfoArr = explode('::', $appListsEncode->financePackage_name);
			$this->jogetPFSApp = $packageFinInfoArr[0];
		}

		$this->db = $CONN;
		$this->dashboard = $dash;
		$this->projectID = $_SESSION['projectID'];
		$this->wpc_id = $_SESSION['wpc_id'];
		$this->project_owner = $_SESSION['project_owner'];
		$this->user_org = $_SESSION['user_org'];
		$this->currPackageUuid = (isset($_SESSION['projectID']) && isset($_SESSION['project_id_number'])) ? $_SESSION['project_id_number']."_". $_SESSION['projectID']. "_" . $_SESSION['project_id_number']: "";
		$this->uiPreference = $_SESSION['ui_pref'];
		$this->parentProjectId = (isset($_SESSION['is_Parent']) && ($_SESSION['is_Parent'] != "isParent") && isset($_SESSION['parent_project_id'])) ? $_SESSION['parent_project_id'] : $_SESSION['projectID'];
		$this->isDownStream = $IS_DOWNSTREAM;
		
		// load joget link
		include_once(dirname(__DIR__).'../Backend/class/jogetLink.class.php');

		$this->jogetLinkObj = new JogetLink();

		$varUse = ($_SESSION['Project_type'] == "ASSET") ? 'asset' : 'joget';
		$this->api_username = $this->jogetLinkObj->getAdminUserName($varUse);
		$this->api_password = $this->jogetLinkObj->getAdminUserPassword($varUse);
		$this->jogetHostIP = $this->jogetLinkObj->jogetHost;

		if (!$ajax) {
			$this->loadJS();
		}

		$this->loadInfo();
	}

