	function loadWorkPackageOption(){
		// parent is overall
		$this->WPCOptions['overall'] = 'Overall';
		$this->WPCOptionsV3['overall'] = 'Overall';

		if($this->project_owner == 'JKR_SABAH'){
			foreach ($this->childProjectInfo as $child) {
				
				$this->WPCOptions[$child['project_id']] = $child['project_wpc_id'];
				$this->WPCOptionsV3[$child['project_id']][$child['package_uuid']] = $child['project_wpc_id'];

			}
		}
		else{
			$skipProjArr = ['WPC01_TMS0100', 'PBHS_Redline'];
			foreach ($this->childProjectInfo as $child) {
				if(in_array($child['project_id'], $skipProjArr)) continue;
				$this->WPCOptions[$child['project_id']] = $child['project_name'].' ('.$child['project_id'].')';
				$this->WPCOptionsV3[$child['project_id']][$child['package_uuid']] = $child['project_name'].' ('.$child['project_id'].')';

			}
		}

		uksort($this->WPCOptions, function($a, $b){
			$aVal = (int) filter_var($a, FILTER_SANITIZE_NUMBER_INT);
			$bVal = (int) filter_var($b, FILTER_SANITIZE_NUMBER_INT);
			if ($aVal > $bVal){
				return 1;
			}
			if ($bVal < $aVal){
				return -1;
			}
		});

		uksort($this->WPCOptionsV3, function($a, $b){
			$aVal = (int) filter_var($a, FILTER_SANITIZE_NUMBER_INT);
			$bVal = (int) filter_var($b, FILTER_SANITIZE_NUMBER_INT);
			if ($aVal > $bVal){
				return 1;
			}
			if ($bVal < $aVal){
				return -1;
			}
		});
	}

	function loadYearOption(){
        $endYear = date("Y",strtotime($this->projectInfo['end_date']));
        $startYear = date("Y",strtotime($this->projectInfo['start_date']));

        $currYear = date("Y");

		$yearDiff = $currYear - $startYear;

        $yr = $currYear + 2;
        for ($i=0; $i < $yearDiff+5 ; $i++) { 
			$this->yearOptions['overall'][] = $yr--; 
        }


		$skipProjArr = ['WPC01_TMS0100', 'PBHS_Redline'];
		foreach ($this->childProjectInfo as $childID) {
			if(in_array($childID['project_id'], $skipProjArr)) continue;

			$endYear = date("Y",strtotime($childID['end_date']));
			$startYear = date("Y",strtotime($childID['start_date']));

			$currYear = date("Y");

			$yearDiff = $currYear - $startYear;

			$yr = $currYear + 2;
			for ($i=0; $i < $yearDiff+5 ; $i++) { 
				$this->yearOptions[$childID['project_id']][] = $yr--; 
			}
		}
	}


	function loadProjectInfo(){
		$this->projectInfo = $this->db->fetchRow("select * from projects where project_id =:0", array($this->projectID));
		if (!$this->projectInfo) die('Failed to retrieve project Information');

		// check image url
		if($this->project_owner == 'JKR_SABAH'){
			$this->projectInfo['icon_url'] = '../Images/Logo_JKR_Sabah.png';
		}
		else if ($this->projectInfo['project_type'] == 'ASSET'){
			$this->projectInfo['icon_url'] = file_exists('../../'.$this->projectInfo['icon_url']) ? '../'.$this->projectInfo['icon_url'] : '../login/revicon2.ico';
		}
		else{
			$this->projectInfo['icon_url'] = file_exists('../'.$this->projectInfo['icon_url']) ? '../'.$this->projectInfo['icon_url'] : '../login/revicon2.ico';
		}
		$this->projectInfo['percentElapse'] = ($this->projectInfo['duration'] && $this->projectInfo['duration'] != 0) ? round(((round((time()-strtotime($this->projectInfo['start_date'])) / (60 * 60 * 24)))/$this->projectInfo['duration'])*100, 2) : 'N/A';

		// check if parent project or not
		$this->isWPC = ($this->projectInfo['parent_project_id_number']) ? true : false;


		// get child project infomation
		$this->childProjectInfo = $this->db->fetchAll("select * from projects where parent_project_id_number = :0 and status = 'active'", array($this->projectInfo['project_id_number']));
		foreach ($this->childProjectInfo as $key => $val) {
			$val['package_uuid'] = $val['project_id_number']."_". $val['project_id']. "_" . $val['project_id_number'];
			$this->childProjectInfo[$key] = $val;
			
		}
	
	}

	function getSectionOption(){

		$sectionUrl = '';
		
		if($this->project_owner == 'JKR_SARAWAK'){
			$sectionUrl = 'list_lookupSection?d-3687296-fn_package_id='.$this->projectID.'&d-3687296-fn_package_uuid=';
			
			if($this->isWPC){
				$res = $this->getCustomDatalistData($sectionUrl.$this->currPackageUuid, 'doc');
				if(isset($res['data']) && $res['data']){
					usort($res['data'], function($a, $b) {
						return strcmp($a["section"], $b["section"]);
					});
					foreach ($res['data'] as $sec) {
						$this->sectionOptions['overall'][] = $sec['section'];
					}
				}
			}
			foreach ($this->childProjectInfo as $child){
				$res = $this->getCustomDatalistData($sectionUrl.$child['package_uuid'], 'doc');
				if (isset($res['data']) && $res['data']) {
					usort($res['data'], function($a, $b) {
						return strcmp($a["section"], $b["section"]);
					});
					foreach ($res['data'] as $sec) {
						$this->sectionOptions[$child['project_id']][] = $sec['section'];
					}
				}
			}

		}else if($this->project_owner == 'SSLR2'){
			// need to change based on lookup id for sslr
			$sectionUrl = 'list_lookupSection_sslr?d-6832753-fn_package_id='.$this->projectID.'&d-6832753-fn_package_uuid=';
			
			if($this->isWPC){
				$res = $this->getCustomDatalistData($sectionUrl.$this->currPackageUuid, 'doc');
				if(isset($res['data']) && $res['data']){
					usort($res['data'], function($a, $b) {
						return strcmp($a["section"], $b["section"]);
					});
					foreach ($res['data'] as $sec) {
						$this->sectionOptions['overall'][] = $sec['section'];
					}
				}
			}
			foreach ($this->childProjectInfo as $child){
				$res = $this->getCustomDatalistData($sectionUrl.$child['package_uuid'], 'doc');
				if (isset($res['data']) && $res['data']) {
					usort($res['data'], function($a, $b) {
						return strcmp($a["section"], $b["section"]);
					});
					foreach ($res['data'] as $sec) {
						$this->sectionOptions[$child['project_id']][] = $sec['section'];
					}
				}
			}
		}
	}

	function loadInfo(){
		$this->loadProjectInfo();
		$this->loadWorkPackageOption();
		$this->loadYearOption();
		if(!$this->isDownStream){
			$this->getSectionOption();
		}
	}

	function getProjectSummary(){
		if($this->project_owner == "JKR_SABAH"){
			$fetchArr = array(
				$this->db->quote($this->projectID)
			);
			foreach ($this->childProjectInfo as $childProj) {
				$fetchArr[] = $this->db->quote($childProj['project_id']);
			}

			$allSummary = $this->db->fetchAll("select * from project_progress_summary where pps_projectid in (".implode(',', $fetchArr).") order by pps_projectid, pps_month_year asc");

			//process to different array
			$monthYear = $finEarly = $finPlan = $finActual = $phyEarly = $phyPlan = $phyAct = array();

			$ret = array();
			$checkValueFlagFin = array();
			$checkValueFlagPhy = array();
			$i = 0;
			foreach ($allSummary as $k => $sum) {
				$projID = ($sum['pps_projectid'] == $this->projectID) ? 'overall' : $sum['pps_projectid'];
				if (!isset($checkValueFlagFin[$projID])) $checkValueFlagFin[$projID] = true;
				if (!isset($checkValueFlagPhy[$projID])) $checkValueFlagPhy[$projID] = true;
				$ret[$projID]["monthYear"][] = $sum['pps_month_year'];  
				$ret[$projID]["finEarly"][] = number_format($sum['pps_financial_early_cm'],2);
				$ret[$projID]["finPlan"][] = number_format($sum['pps_financial_late_cm'],2);
				$ret[$projID]["finActual"][] = ($sum['pps_financial_actual']) ? number_format($sum['pps_financial_actual'],2) : null;
				$ret[$projID]["phyEarly"][] = number_format($sum['pps_physical_early'],2);
				$ret[$projID]["phyPlan"][] = number_format($sum['pps_physical_late'],2);
				$ret[$projID]["phyAct"][] =  ($sum['pps_physical_actual']) ? number_format($sum['pps_physical_actual'],2) : null;

				// need to appy same logic as in projectSummary js (when actual goes down we wont show it), here it become zero
				//late = actual, early = schedule/plan
				$finVar = (float) $sum['pps_financial_late_cm'] - (float) $sum['pps_financial_early_cm']; 
				$phyVar = (float) $sum['pps_physical_late'] - (float) $sum['pps_physical_early'];

				if($i != 0){
					if(isset($allSummary[$k-1]['pps_financial_late_cm']) && (float) $sum['pps_financial_late_cm'] == '0.00' && (float) $sum['pps_financial_late_cm'] <= (float) $allSummary[$k-1]['pps_financial_late_cm']) {
						$finVar = '0.00';
					}

					if(isset($allSummary[$k-1]['pps_physical_late']) && (float) $sum['pps_physical_late'] == '0.00' && (float) $sum['pps_physical_late'] <= (float) $allSummary[$k-1]['pps_physical_late']){
						$phyVar = '0.00';
					}
				}				

				$sum['pps_financial_var'] = number_format($finVar,2);
				$sum['pps_physical_var'] = number_format($phyVar,2);

				$ret[$projID]['raw'][] =  $sum;
				$i++;
			}
		}
		else{
			$fetchArr = array(
				$this->db->quote($this->projectID)
			);
			foreach ($this->childProjectInfo as $childProj) {
				$fetchArr[] = $this->db->quote($childProj['project_id']);
			}

			$allSummary = $this->db->fetchAll("select * from project_progress_summary where pps_projectid in (".implode(',', $fetchArr).") order by pps_projectid, pps_month_year asc");

			//process to different array
			$monthYear = $finEarly = $finPlan = $finActual = $phyEarly = $phyPlan = $phyAct = array();

			$ret = array();
			foreach ($allSummary as $sum) {
				$projID = ($sum['pps_projectid'] == $this->projectID) ? 'overall' : $sum['pps_projectid'];
				$ret[$projID]["monthYear"][] = $sum['pps_month_year']; 
				$ret[$projID]["finEarly"][] = number_format($sum['pps_financial_early_cm'],2);
				$ret[$projID]["finPlan"][] = number_format($sum['pps_financial_late_cm'],2);
				$ret[$projID]["finActual"][] = ($sum['pps_financial_actual']) ? number_format($sum['pps_financial_actual'],2) : null;
				$ret[$projID]["phyEarly"][] = number_format($sum['pps_physical_early'],2);
				$ret[$projID]["phyPlan"][] = number_format($sum['pps_physical_late'],2);
				$ret[$projID]["phyAct"][] =  ($sum['pps_physical_actual']) ? number_format($sum['pps_physical_actual'],2) : null;

				$finVar = (float) $sum['pps_financial_late_cm'] - (float) $sum['pps_financial_early_cm']; 
				$phyVar = (float) $sum['pps_physical_late'] - (float) $sum['pps_physical_early']; 
				$sum['pps_financial_var'] = number_format($finVar,2);
				$sum['pps_physical_var'] = number_format($phyVar,2);

				$ret[$projID]['raw'][] =  $sum;
			}
		}

		return $ret;
	}

	function getProjectSummaryInfo(){

		$tempProjInfoArr = array();
		if($this->project_owner == 'JKR_SABAH'){
			foreach ($this->childProjectInfo as $childArr) {
				$tempProjInfoArr[$childArr['project_wpc_id']] = $childArr;
			}
		}
		else{
			foreach ($this->childProjectInfo as $childArr) {
				$tempProjInfoArr[$childArr['project_id']] = $childArr;
			}
		}

		$tempProjInfoArr['overall'] = $this->projectInfo;

		$ret = array(
			'projectSummaryData' => $this->getProjectSummary(),
			'projInfo' => $tempProjInfoArr,
			'ui_pref' => $_SESSION['ui_pref']
		);
		return $ret;
	}

	function fetchPDPCriticalRiskDriverData(){
		$ret = array();
		$keyArr = array();
		$colorArray = ['#FF6633', '#FFB399', '#FF33FF', '#FFFF99', '#00B3E6', '#E6B333', '#3366E6', '#999966', '#99FF99', '#B34D4D','#80B300', '#809900', '#E6B3B3', '#6680B3', '#66991A', '#FF99E6', '#CCFF1A', '#FF1A66', '#E6331A', '#33FFCC','#66994D', '#B366CC', '#4D8000', '#B33300', '#CC80CC', '#66664D', '#991AFF', '#E666FF', '#4DB3FF', '#1AB399','#E666B3', '#33991A', '#CC9999', '#B3B31A', '#00E680', '#4D8066', '#809980', '#E6FF80', '#1AFF33', '#999933','#FF3380', '#CCCC00', '#66E64D', '#4D80CC', '#9900B3', '#E64D66', '#4DB380', '#FF4D4D', '#99E6E6', '#6666FF'];
		$i = 0;
		
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_RR', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
