	function fetchPDPOverallDurationAnalysis(){
		// get only for this month
		$ret = array();

		$overallData = $this->db->fetchAll("select * from risk_histogram_data where rhd_ruf_id = (select max(ruf_id) from risk_uploaded_file where ruf_projectId = :0) ORDER BY CAST(rhd_bins AS FLOAT), rhd_month_year asc", array($this->projectInfo['project_id']));
		$ret['overall']['all']['all']['rawData'] = $overallData;

		foreach ($overallData as $od) {
			$dt = strtotime($od['rhd_month_year']);
			$year = date("Y", $dt);
			$month = date("m", $dt);

			$ret['overall']['all']['all']['bin'][] = $od['rhd_bins'];
			$ret['overall'][$year]['all']['bin'][] = $od['rhd_bins'];
			$ret['overall'][$year][$month]['bin'][] = $od['rhd_bins'];

			$ret['overall']['all']['all']['count'][] = $od['rhd_count'];
			$ret['overall'][$year]['all']['count'][] = $od['rhd_count'];
			$ret['overall'][$year][$month]['count'][] = $od['rhd_count'];

			$ret['overall']['all']['all']['cum'][] = $od['rhd_cum'];
			$ret['overall'][$year]['all']['cum'][] = $od['rhd_cum'];
			$ret['overall'][$year][$month]['cum'][] = $od['rhd_cum'];
		}

		foreach ($this->childProjectInfo as $childID) {
			$overallDataChild = $this->db->fetchAll("select * from risk_histogram_data where rhd_ruf_id = (select max(ruf_id) from risk_uploaded_file where ruf_projectId = :0) ORDER BY CAST(rhd_bins AS FLOAT), rhd_month_year asc", array($childID['project_id']));
			$ret[$childID['project_id']]['all']['all']['rawData'] = $overallDataChild;

			foreach ($overallDataChild as $d) {
				$dt = strtotime($d['rhd_month_year']);
				$year = date("Y", $dt);
				$month = date("m", $dt);

				$ret[$childID['project_id']]['all']['all']['bin'][] = $d['rhd_bins'];
				$ret[$childID['project_id']][$year]['all']['bin'][] = $d['rhd_bins'];
				$ret[$childID['project_id']][$year][$month]['bin'][] = $d['rhd_bins'];

				$ret[$childID['project_id']]['all']['all']['count'][] = $d['rhd_count'];
				$ret[$childID['project_id']][$year]['all']['count'][] = $d['rhd_count'];
				$ret[$childID['project_id']][$year][$month]['count'][] = $d['rhd_count'];

				$ret[$childID['project_id']]['all']['all']['cum'][] = $d['rhd_cum'];
				$ret[$childID['project_id']][$year]['all']['cum'][] = $d['rhd_cum'];
				$ret[$childID['project_id']][$year][$month]['cum'][] = $d['rhd_cum'];
			}
		}
		return $ret;
	}

	function fetchRiskProbabilityData(){
		$ret = array();

		$sql = "SELECT rpd_project_remain_dur, rpd_project_prob_complete, rpd_overall_schedule_impact_uncer, rpd_timely_completion_prob, rpd_month_year
				FROM risk_probability_data
				WHERE rpd_projectId = :0
				ORDER BY rpd_month_year ASC
				";

		if ($this->isWPC) {
			$mainRes = $this->db->fetchAll($sql, array($this->projectID));

			foreach ($mainRes as $val) {
				$dt = strtotime($val['rpd_month_year']);
				$year = date("Y", $dt);
				$month = date("m", $dt);

				$ret['overall']['all']['all']['overall'] = $val;
				$ret['overall'][$year]['all']['overall'] = $val;
				$ret['overall'][$year][$month]['overall'] = $val;
			}
		}

		// this will be empty if $this->isWPC = true
		foreach ($this->childProjectInfo as $childID) {
			$res = $this->db->fetchAll($sql, array($childID['project_id']));
			foreach ($res as $val) {
				$dt = strtotime($val['rpd_month_year']);
				$year = date("Y", $dt);
				$month = date("m", $dt);

				$ret[$childID['project_id']]['all']['all'][$childID['project_id']] = $val;
				$ret[$childID['project_id']][$year]['all'][$childID['project_id']] = $val;
				$ret[$childID['project_id']][$year][$month][$childID['project_id']] = $val;
			}
		}
		return $ret;
	}

	function fetchRiskInfo(){
		$ret = array();
		$ret['option']['cat'] = array();
		$ret['option']['rating'] = array();

		$riskRatingOrder = ['Low', 'Medium', 'Serious', 'Significant', 'High', 'Others'];
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_RR', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			if ($res['data']) {

				usort($res['data'], function ($a, $b) use ($riskRatingOrder) {
					$aIndex = array_search($a['risk'], $riskRatingOrder);
					$bIndex = array_search($b['risk'], $riskRatingOrder);
					return $aIndex - $bIndex;
				});

				foreach ($res['data'] as $risk) {
					if (!in_array($risk['c_risk_category'], $ret['option']['cat'])) {
						$ret['option']['cat'][] = $risk['c_risk_category'];
					}
					$risk['risk'] = ($risk['risk']) ? $risk['risk'] : 'Others';
					if (!in_array($risk['risk'], $ret['option']['rating'])) {
						$ret['option']['rating'][] = $risk['risk'];
					}

					$dateCreated = strtotime($risk['dateCreated']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					// wpc->cat->rating				
					// total
					if (isset($ret['overall']['overall']['overall']['card']['all']['all']['total'])) {
						$ret['overall']['overall']['overall']['card']['all']['all']['total']++;
					}else{
						$ret['overall']['overall']['overall']['card']['all']['all']['total'] = 1;
					}
					if (isset($ret['overall']['overall']['overall']['card'][$year]['all']['total'])) {
						$ret['overall']['overall']['overall']['card'][$year]['all']['total']++;
					}else{
						$ret['overall']['overall']['overall']['card'][$year]['all']['total'] = 1;
					}
					if (isset($ret['overall']['overall']['overall']['card'][$year][$month]['total'])) {
						$ret['overall']['overall']['overall']['card'][$year][$month]['total']++;
					}else{
						$ret['overall']['overall']['overall']['card'][$year][$month]['total'] = 1;
					}

					if (isset($ret['overall'][$risk['c_risk_category']]['overall']['card']['all']['all']['total'])) {
						$ret['overall'][$risk['c_risk_category']]['overall']['card']['all']['all']['total']++;
					}else{
						$ret['overall'][$risk['c_risk_category']]['overall']['card']['all']['all']['total'] = 1;
					}
					if (isset($ret['overall'][$risk['c_risk_category']]['overall']['card'][$year]['all']['total'])) {
						$ret['overall'][$risk['c_risk_category']]['overall']['card'][$year]['all']['total']++;
					}else{
						$ret['overall'][$risk['c_risk_category']]['overall']['card'][$year]['all']['total'] = 1;
					}
					if (isset($ret['overall'][$risk['c_risk_category']]['overall']['card'][$year][$month]['total'])) {
						$ret['overall'][$risk['c_risk_category']]['overall']['card'][$year][$month]['total']++;
					}else{
						$ret['overall'][$risk['c_risk_category']]['overall']['card'][$year][$month]['total'] = 1;
					}


					if (isset($ret['overall'][$risk['c_risk_category']][$risk['risk']]['card']['all']['all']['total'])) {
						$ret['overall'][$risk['c_risk_category']][$risk['risk']]['card']['all']['all']['total']++;
					}else{
						$ret['overall'][$risk['c_risk_category']][$risk['risk']]['card']['all']['all']['total'] = 1;
					}
					if (isset($ret['overall'][$risk['c_risk_category']][$risk['risk']]['card'][$year]['all']['total'])) {
						$ret['overall'][$risk['c_risk_category']][$risk['risk']]['card'][$year]['all']['total']++;
					}else{
						$ret['overall'][$risk['c_risk_category']][$risk['risk']]['card'][$year]['all']['total'] = 1;
					}
					if (isset($ret['overall'][$risk['c_risk_category']][$risk['risk']]['card'][$year][$month]['total'])) {
						$ret['overall'][$risk['c_risk_category']][$risk['risk']]['card'][$year][$month]['total']++;
					}else{
						$ret['overall'][$risk['c_risk_category']][$risk['risk']]['card'][$year][$month]['total'] = 1;
					}

					if (isset($ret['overall']['overall'][$risk['risk']]['card']['all']['all']['total'])) {
						$ret['overall']['overall'][$risk['risk']]['card']['all']['all']['total']++;
					}else{
						$ret['overall']['overall'][$risk['risk']]['card']['all']['all']['total'] = 1;
					}
					if (isset($ret['overall']['overall'][$risk['risk']]['card'][$year]['all']['total'])) {
						$ret['overall']['overall'][$risk['risk']]['card'][$year]['all']['total']++;
					}else{
						$ret['overall']['overall'][$risk['risk']]['card'][$year]['all']['total'] = 1;
					}
					if (isset($ret['overall']['overall'][$risk['risk']]['card'][$year][$month]['total'])) {
						$ret['overall']['overall'][$risk['risk']]['card'][$year][$month]['total']++;
					}else{
						$ret['overall']['overall'][$risk['risk']]['card'][$year][$month]['total'] = 1;
					}

					// close / pending
					if (isset($ret['overall']['overall']['overall']['card']['all']['all'][$risk['c_status']])) {
						$ret['overall']['overall']['overall']['card']['all']['all'][$risk['c_status']]++;
					}else{
						$ret['overall']['overall']['overall']['card']['all']['all'][$risk['c_status']] = 1;
					}
					if (isset($ret['overall'][$risk['c_risk_category']]['overall']['card']['all']['all'][$risk['c_status']])) {
						$ret['overall'][$risk['c_risk_category']]['overall']['card']['all']['all'][$risk['c_status']]++;
					}else{
						$ret['overall'][$risk['c_risk_category']]['overall']['card']['all']['all'][$risk['c_status']] = 1;
					}
					if (isset($ret['overall'][$risk['c_risk_category']][$risk['risk']]['card']['all']['all'][$risk['c_status']])) {
