	function fetchTrendAlertInfo(){
		$ret = array();
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_doc_register_doc', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			if (isset($res['data'])) {
				foreach ($res['data'] as $trend) {
					if ($trend['c_doc_type'] == 'Trend Alert') {
						if (isset($ret['overall']['card']['total'])) {
							$ret['overall']['card']['total']++;
						}else{
							$ret['overall']['card']['total'] = 1;
						}
					}
				}
			}
		}else{
			$url = $this->jogetLinkObj->getLink('dash_doc_register_doc', array('', $this->projectID));
			$res = $this->jogetCURL($url);
			if (isset($res['data'])) {
				foreach ($res['data'] as $trend) {
					if ($trend['c_doc_type'] == 'Trend Alert') {
						if (isset($ret['overall']['card']['total'])) {
							$ret['overall']['card']['total']++;
						}else{
							$ret['overall']['card']['total'] = 1;
						}

						//----------START CHILD-------------//
						if (isset($ret[$trend['c_package_id']]['card']['total'])) {
							$ret[$trend['c_package_id']]['card']['total']++;
						}else{
							$ret[$trend['c_package_id']]['card']['total'] = 1;
						}
						//-------------END CHILD------------//
					}
				}
			}
		}
		return $ret;
	}

	function getRiskInfo(){
		if ($this->project_owner == 'JKR_SABAH') {
			$ret = array(
				'risk' => $this->fetchRiskInfo(),
				'trendAlert' => $this->fetchTrendAlertInfo()
			);			
		} else if($this->project_owner == 'SSLR2') {
			$ret = array(
				// joget sslr2
				'pdp' =>  $this->fetchPDPCriticalRiskDriverDataSSLR(),
				// timely, overall, probability - local db
				'riskProb' => $this->fetchRiskProbabilityData(),
				// histogram - local db
				'pdpODAHistogram' => $this->fetchPDPOverallDurationAnalysis()
			);
		}else{
			$ret = array(
				// joget
				'pdp' =>  $this->fetchPDPCriticalRiskDriverData(),
				// timely, overall, probability - local db
				'riskProb' => $this->fetchRiskProbabilityData(),
				// histogram - local db
				'pdpODAHistogram' => $this->fetchPDPOverallDurationAnalysis()
			);
		}
		
		return $ret;
	}

	function getBumiInfo(){
		// get based on projects and filter by wpc
		$ret = array();
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_BP').$this->currPackageUuid;
			$res = $this->jogetCURL($url);

			if (isset($res['data'])) {
				foreach ($res['data'] as $bumi) {
					if ($this->projectID != $bumi['packageId']) continue;
					switch (strtolower($bumi['participant_status'])) {
						case 'receive loa':
							$bumi['color'] = 'lime';
							break;
						case 'potential deal':
							$bumi['color'] = 'yellow';
							break;
						case 'hard case':
							$bumi['color'] = 'red';
							break;											
						default:
							$bumi['color'] = '';
							break;
					}

					$ret['overall']['overall']['raw'][] = $bumi;
					$ret['overall'][$bumi['category']]['raw'][] = $bumi;
					// package -> category
					$ret[$bumi['packageId']]['overall']['raw'][] = $bumi;
					$ret[$bumi['packageId']][$bumi['category']]['raw'][] = $bumi;

					if (isset($ret['overall']['overall']['cnt']['consortium']))
						$ret['overall']['overall']['cnt']['consortium']++;
					else
						$ret['overall']['overall']['cnt']['consortium'] = 1;

					if (isset($ret['overall']['overall']['cnt'][strtolower($bumi['category'])]))
						$ret['overall']['overall']['cnt'][strtolower($bumi['category'])]++;
