	function fetchUrwWorkInfo(){
		$ret = array();
		if ($this->isWPC) {
			//RFI Sabah is WIR Sarawak
			
			if(isset($this->rfiDataAPI['data']) && $this->rfiDataAPI['data']){
				$res = $this->rfiDataAPI ;
			}else{
				$url = $this->jogetLinkObj->getLink('dash_cons_RFI_urw', array($this->currPackageUuid, ''));
				$res = $this->jogetCURL($url);
			}
 
			if (isset($res['data'])) {
