	function fetchProgressUpdate(){
		$ret = array();
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_PU', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			if (isset($res['data'])) {
				usort($res['data'], function($a, $b) {
					return strcmp($a['utility_provider'], $b['utility_provider']);
				});
				foreach ($res['data'] as $pu) {
					$ret['overall']['overall']['all']['all']['raw'][] = $pu;
					$ret['overall']['overall'][$pu['year']]['all']['raw'][] = $pu;
					$ret['overall']['overall'][$pu['year']][$pu['month']]['raw'][] = $pu;
				}
			}
		}
		else{
			$url = $this->jogetLinkObj->getLink('dash_cons_PU', array('', $this->projectID));
			$res = $this->jogetCURL($url);
			if (isset($res['data'])) {
				usort($res['data'], function($a, $b) {
					return strcmp($a['utility_provider'], $b['utility_provider']);
				});
				foreach ($res['data'] as $pu) {
					$ret['overall']['overall']['all']['all']['raw'][] = $pu;
					$ret['overall']['overall'][$pu['year']]['all']['raw'][] = $pu;
					$ret['overall']['overall'][$pu['year']][$pu['month']]['raw'][] = $pu;

					//-----------------START CHILD------------------//
					$ret[$pu['package_id']]['overall']['all']['all']['raw'][] = $pu;
					$ret[$pu['package_id']]['overall'][$pu['year']]['all']['raw'][] = $pu;
					$ret[$pu['package_id']]['overall'][$pu['year']][$pu['month']]['raw'][] = $pu;

					//------------------END CHILD-------------------//
					
				}
			}
		}

		return $ret;
	}

	function getUtilitiesInfo(){

		if ($this->project_owner == 'JKR_SABAH') {
			$urw_flag = true;
			$ret = array(
				"rfi" => $this->fetchRFIInfo($urw_flag),
				"all" => $this->fetchUrwWorkInfo(),
				"utilities" => $this->fetchProgressUpdate()
			);
		}

		return $ret;
	}

	function processLandEncData($data){
		$data['total_length'] = isset($data['total_length']) ? (double) str_replace(',', '', $data['total_length']) : 0;
		$data['free_encumbrances'] = isset($data['free_encumbrances']) ? (double) str_replace(',', '', $data['free_encumbrances']) : 0;
		$data['total_encumbrances'] = isset($data['total_encumbrances']) ? (double) str_replace(',', '', $data['total_encumbrances']) : 0;
		return $data;
	}

	function fetchLandIssueDataSSLR(){
		// by this month and latest only for each wpc
		$ret = array();
		$statusOption = array();
		$sectionOption = array();
		$currMonYr = date('m-Y');
		$currMonYrFilter = date('Y-m'); // in java format for date

		// if not overall
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_LI', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);

			if (isset($res['data'])) {
				foreach ($res['data'] as $li) {
					$date = new DateTime($li['dateCreated']);
					if ($date) {
						$li['dateCreated'] = $date->format('d-m-Y h:i:s A');
					}

					// based on month and year
					$dateCreated = strtotime($li['dateCreated']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);
					
					//filter for all
					$ret['overall']['all']['all']['tableLi']['overall']['all'][] = $li;
					$ret['overall'][$year]['all']['tableLi']['overall']['all'][] = $li;
					$ret['overall'][$year][$month]['tableLi']['overall']['all'][] = $li;

					//filter by status
					$ret['overall']['all']['all']['tableLi']['overall'][$li['view_issue_status']][] = $li;
					$ret['overall'][$year]['all']['tableLi']['overall'][$li['view_issue_status']][] = $li;
					$ret['overall'][$year][$month]['tableLi']['overall'][$li['view_issue_status']][] = $li;

					//filter by section & status all
					$ret['overall']['all']['all']['tableLi'][$li['c_section']]['all'][] = $li;
					$ret['overall'][$year]['all']['tableLi'][$li['c_section']]['all'][] = $li;
					$ret['overall'][$year][$month]['tableLi'][$li['c_section']]['all'][] = $li;

					//filter by section & status
					$ret['overall']['all']['all']['tableLi'][$li['c_section']][$li['view_issue_status']][] = $li;
					$ret['overall'][$year]['all']['tableLi'][$li['c_section']][$li['view_issue_status']][] = $li;
					$ret['overall'][$year][$month]['tableLi'][$li['c_section']][$li['view_issue_status']][] = $li;

					// for status option filtering
					if ($li['view_issue_status'] && !in_array($li['view_issue_status'], $statusOption)) array_push($statusOption, $li['view_issue_status']);

					// for section option filtering
					if ($li['c_section'] && !in_array($li['c_section'], $sectionOption)) array_push($sectionOption, $li['c_section']);
				}
			}
		}
		else{
			$url = $this->jogetLinkObj->getLink('dash_cons_LI', array('', $this->projectID));
			$res = $this->jogetCURL($url);
			if (isset($res['data'])) {
				foreach ($res['data'] as $li) {
					$date = new DateTime($li['dateCreated']);
					if ($date) {
						$li['dateCreated'] = $date->format('d-m-Y h:i:s A');
					}

					// based on month and year
					$dateCreated = strtotime($li['dateCreated']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);
					
					//filter for all
					$ret['overall']['all']['all']['tableLi']['overall']['all'][] = $li;
					$ret['overall'][$year]['all']['tableLi']['overall']['all'][] = $li;
					$ret['overall'][$year][$month]['tableLi']['overall']['all'][] = $li;

					//filter by package
					$ret[$li['package_id']]['all']['all']['tableLi']['overall']['all'][] = $li;
					$ret[$li['package_id']][$year]['all']['tableLi']['overall']['all'][] = $li;
					$ret[$li['package_id']][$year][$month]['tableLi']['overall']['all'][] = $li;

					//filter by status
					$ret['overall']['all']['all']['tableLi']['overall'][$li['view_issue_status']][] = $li;
					$ret['overall'][$year]['all']['tableLi']['overall'][$li['view_issue_status']][] = $li;
					$ret['overall'][$year][$month]['tableLi']['overall'][$li['view_issue_status']][] = $li;

					//filter by package & status
					$ret[$li['package_id']]['all']['all']['tableLi']['overall'][$li['view_issue_status']][] = $li;
					$ret[$li['package_id']][$year]['all']['tableLi']['overall'][$li['view_issue_status']][] = $li;
					$ret[$li['package_id']][$year][$month]['tableLi']['overall'][$li['view_issue_status']][] = $li;

					//filter by section & status all
					$ret['overall']['all']['all']['tableLi'][$li['c_section']]['all'][] = $li;
					$ret['overall'][$year]['all']['tableLi'][$li['c_section']]['all'][] = $li;
					$ret['overall'][$year][$month]['tableLi'][$li['c_section']]['all'][] = $li;

					//filter by section & status all
					$ret[$li['package_id']]['all']['all']['tableLi'][$li['c_section']]['all'][] = $li;
					$ret[$li['package_id']][$year]['all']['tableLi'][$li['c_section']]['all'][] = $li;
					$ret[$li['package_id']][$year][$month]['tableLi'][$li['c_section']]['all'][] = $li;

					//filter by section & status
					$ret['overall']['all']['all']['tableLi'][$li['c_section']][$li['view_issue_status']][] = $li;
					$ret['overall'][$year]['all']['tableLi'][$li['c_section']][$li['view_issue_status']][] = $li;
					$ret['overall'][$year][$month]['tableLi'][$li['c_section']][$li['view_issue_status']][] = $li;

					//filter by package, section & status
					$ret[$li['package_id']]['all']['all']['tableLi'][$li['c_section']][$li['view_issue_status']][] = $li;
					$ret[$li['package_id']][$year]['all']['tableLi'][$li['c_section']][$li['view_issue_status']][] = $li;
					$ret[$li['package_id']][$year][$month]['tableLi'][$li['c_section']][$li['view_issue_status']][] = $li;

					// for status option filtering
					if ($li['view_issue_status'] && !in_array($li['view_issue_status'], $statusOption)) array_push($statusOption, $li['view_issue_status']);

					// for section option filtering
					if ($li['c_section'] && !in_array($li['c_section'], $sectionOption)) array_push($sectionOption, $li['c_section']);
				}
			}
		}

		$ret['issueStatusOption'] = $statusOption;
		$ret['issueSectionOption'] = $sectionOption;
		return $ret;
	}

