	function fetchLandIssueData(){
		// by this month and latest only for each wpc
		$ret = array();
		$sourcesOption = array();
		$currMonYr = date('m-Y');
		$currMonYrFilter = date('Y-m'); // in java format for date

		// if not overall
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_LI', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);

			if (isset($res['data'])) {
				foreach ($res['data'] as $li) {
					$date = new DateTime($li['dateCreated']);
					if ($date) {
						$li['dateCreated'] = $date->format('d-m-Y h:i:s A');
					}
					$ret['overall']['all']['all'][] = $li;
					$ret['overall']['all'][$li['c_source']][] = $li; 	
					$ret['overall'][$li['issueStatus']]['all'][] = $li;
					$ret['overall'][$li['issueStatus']][$li['c_source']][] = $li;

					if ($li['c_source'] && !in_array($li['c_source'], $sourcesOption)) array_push($sourcesOption, $li['c_source']);
				}
			}
		}
		else{
			$url = $this->jogetLinkObj->getLink('dash_cons_LI', array('', $this->projectID));
			$res = $this->jogetCURL($url);
			if (isset($res['data'])) {
				foreach ($res['data'] as $li) {
					$date = new DateTime($li['dateCreated']);
					if ($date) {
						$li['dateCreated'] = $date->format('d-m-Y h:i:s A');
					}
					$ret['overall']['all']['all'][] = $li;
					$ret['overall']['all'][$li['c_source']][] = $li; 	
					$ret['overall'][$li['issueStatus']]['all'][] = $li;
					$ret['overall'][$li['issueStatus']][$li['c_source']][] = $li;

					$ret[$li['package_id']]['all']['all'][] = $li;
					$ret[$li['package_id']]['all'][$li['c_source']][] = $li; 	
					$ret[$li['package_id']][$li['issueStatus']]['all'][] = $li;	
					$ret[$li['package_id']][$li['issueStatus']][$li['c_source']][] = $li;

					// for status option filtering
					if ($li['c_source'] && !in_array($li['c_source'], $sourcesOption)) array_push($sourcesOption, $li['c_source']);
				}
			}
		}

		$ret['issueSourcesOption'] = $sourcesOption;
		return $ret;
	}

