				$ret['encData']['overall']['encumbrances']  = ($overallTotalLength != 0 && $overallTotalLength > $overallTotalEnc) ?  number_format(($overallTotalEnc/$overallTotalLength)*100, 2) : 0;
			}

		}
		else{
			$url = $this->jogetLinkObj->getLink('dash_cons_LE', array('', $this->projectID));
			$res = $this->jogetCURL($url);
			if (isset($res['data'])){
				$arrPackageID = array();
				foreach($res['data'] as $eachLandData) {
					$ret['encData']['overall'] = $eachLandData;
					$overallFreeEnc = $overallFreeEnc + (float) str_replace(',', '', $eachLandData['free_encumbrances']);
					$overallTotalLength = $overallTotalLength + (float) str_replace(',', '',   $eachLandData['total_length']);
					$overallTotalEnc = $overallTotalEnc + (float) str_replace(',', '',  $eachLandData['total_encumbrances']);
					$ret['encData']['overall']['free_encumbrances'] = $overallFreeEnc;
					$ret['encData']['overall']['total_length'] = $overallTotalLength;
					$ret['encData']['overall']['total_encumbrances'] = $overallTotalEnc;

					$ret['encData'][$eachLandData['package_id']] = $eachLandData;
					$overallFreeEnc = $overallFreeEnc + (float) str_replace(',', '', $eachLandData['free_encumbrances']);
					$overallTotalLength = $overallTotalLength + (float) str_replace(',', '',   $eachLandData['total_length']);
					$overallTotalEnc = $overallTotalEnc + (float) str_replace(',', '',  $eachLandData['total_encumbrances']);
					$ret['encData'][$eachLandData['package_id']]['free_encumbrances'] = $overallFreeEnc;
					$ret['encData'][$eachLandData['package_id']]['total_length'] = $overallTotalLength;
					$ret['encData'][$eachLandData['package_id']]['total_encumbrances'] = $overallTotalEnc;
				}
				$ret['encData']['overall']['foc']  = ($overallTotalLength != 0 && $overallTotalLength > $overallFreeEnc) ?  number_format(($overallFreeEnc/$overallTotalLength)*100, 2) : 0;
				$ret['encData']['overall']['encumbrances']  = ($overallTotalLength != 0 && $overallTotalLength > $overallTotalEnc) ?  number_format(($overallTotalEnc/$overallTotalLength)*100, 2) : 0;
			
				foreach ($arrPackageID as $pk) {
					$ret['encData'][$pk]['foc']  = ($overallTotalLength != 0 && $overallTotalLength > $overallFreeEnc) ?  number_format(($overallFreeEnc/$overallTotalLength)*100, 2) : 0;
					$ret['encData'][$pk]['encumbrances']  = ($overallTotalLength != 0 && $overallTotalLength > $overallTotalEnc) ?  number_format(($overallTotalEnc/$overallTotalLength)*100, 2) : 0;
				}
			
			}
		}

		$ret['encCardData']['totalFOE'] = ($overallTotalLength != 0 && $overallTotalLength > $overallFreeEnc) ?  number_format(($overallFreeEnc/$overallTotalLength)*100, 2) : 0;
		$ret['encCardData']['totalEnc'] = ($overallTotalLength != 0 && $overallTotalLength > $overallTotalEnc) ?  number_format(($overallTotalEnc/$overallTotalLength)*100, 2) : 0;
		return $ret;
	}

