	function getLCMNoList(){
		$ret = array();
		$districtUrl = 'list_lookupDistrict?d-2647551-fn_package_id='.$this->projectID.'&d-2647551-fn_package_uuid=';

		if($this->isWPC){
			$url = $this->jogetLinkObj->getLink('dash_cons_LS', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			//FOR FILTER LCM
			if(isset($res['data']) && $res['data']){
				usort($res['data'], function($a, $b) {
				    return strcmp($a["lcm_no"], $b["lcm_no"]);
				});
				
				foreach ($res['data'] as $lcm) {
					if($lcm['lcm_no'] == '') continue;

					if(isset ($ret['overall']['allDistrict']['all']['all'])){
						if (!in_array($lcm['lcm_no'], $ret['overall']['allDistrict']['all']['all'])) {
							$ret['overall']['allDistrict']['all']['all'][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret['overall']['allDistrict']['all']['all'][] = $lcm['lcm_no'];
					}

					if(isset($ret['overall']['allDistrict'][$lcm['year']]['all'])){
						if (!in_array($lcm['lcm_no'], $ret['overall']['allDistrict'][$lcm['year']]['all'])) {
							$ret['overall']['allDistrict'][$lcm['year']]['all'][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret['overall']['allDistrict'][$lcm['year']]['all'][] = $lcm['lcm_no'];

					}

					if(isset($ret['overall']['allDistrict'][$lcm['year']][$lcm['month']])){
						if (!in_array($lcm['lcm_no'], $ret['overall']['allDistrict'][$lcm['year']][$lcm['month']])) {
							$ret['overall']['allDistrict'][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret['overall']['allDistrict'][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
					}

					if(isset($ret['changeFilter']['overall']['allDistrict'][$lcm['year']][$lcm['month']])){
						if (!in_array($lcm['lcm_no'], $ret['changeFilter']['overall']['allDistrict'][$lcm['year']][$lcm['month']])) {
							$ret['changeFilter']['overall']['allDistrict'][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret['changeFilter']['overall']['allDistrict'][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
					}

					if(isset($ret['overall'][$lcm['district']]['all']['all'])){
						if (!in_array($lcm['lcm_no'], $ret['overall'][$lcm['district']]['all']['all'])) {
							$ret['overall'][$lcm['district']]['all']['all'][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret['overall'][$lcm['district']]['all']['all'][] = $lcm['lcm_no'];
					}
					
					if(isset($ret['overall'][$lcm['district']][$lcm['year']]['all'])){
						if (!in_array($lcm['lcm_no'], $ret['overall'][$lcm['district']][$lcm['year']]['all'])) {
							$ret['overall'][$lcm['district']][$lcm['year']]['all'][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret['overall'][$lcm['district']][$lcm['year']]['all'][] = $lcm['lcm_no'];
					}

					if(isset($ret['overall'][$lcm['district']][$lcm['year']][$lcm['month']])){
						if (!in_array($lcm['lcm_no'], $ret['overall'][$lcm['district']][$lcm['year']][$lcm['month']])) {
							$ret['overall'][$lcm['district']][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret['overall'][$lcm['district']][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
					}


					if(isset($ret['changeFilter']['overall'][$lcm['district']][$lcm['year']][$lcm['month']])){
						if (!in_array($lcm['lcm_no'], $ret['changeFilter']['overall'][$lcm['district']][$lcm['year']][$lcm['month']])) {
							$ret['changeFilter']['overall'][$lcm['district']][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret['changeFilter']['overall'][$lcm['district']][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
					}

				}
			}
		}
		else{
			$url = $this->jogetLinkObj->getLink('dash_cons_LS', array('', $this->projectID));
			$res = $this->jogetCURL($url);
			
			//FOR FILTER LCM
			if (isset($res['data']) && $res['data']) {
				usort($res['data'], function($a, $b) {
				    return strcmp($a["lcm_no"], $b["lcm_no"]);
				});
				foreach ($res['data'] as $lcm) {
					if($lcm['lcm_no'] == '') continue;

					if(isset ($ret[$lcm['package_id']]['allDistrict']['all']['all'])){
						if (!in_array($lcm['lcm_no'], $ret[$lcm['package_id']]['allDistrict']['all']['all'])) {
							$ret[$lcm['package_id']]['allDistrict']['all']['all'][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret[$lcm['package_id']]['allDistrict']['all']['all'][] = $lcm['lcm_no'];
					}

					if(isset($ret[$lcm['package_id']]['allDistrict'][$lcm['year']]['all'])){
						if (!in_array($lcm['lcm_no'], $ret[$lcm['package_id']]['allDistrict'][$lcm['year']]['all'])) {
							$ret[$lcm['package_id']]['allDistrict'][$lcm['year']]['all'][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret[$lcm['package_id']]['allDistrict'][$lcm['year']]['all'][] = $lcm['lcm_no'];

					}

					if(isset($ret[$lcm['package_id']]['allDistrict'][$lcm['year']][$lcm['month']])){
						if (!in_array($lcm['lcm_no'], $ret[$lcm['package_id']]['allDistrict'][$lcm['year']][$lcm['month']])) {
							$ret[$lcm['package_id']]['allDistrict'][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret[$lcm['package_id']]['allDistrict'][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
					}

					if(isset($ret['changeFilter'][$lcm['package_id']]['allDistrict'][$lcm['year']][$lcm['month']])){
						if (!in_array($lcm['lcm_no'], $ret['changeFilter'][$lcm['package_id']]['allDistrict'][$lcm['year']][$lcm['month']])) {
							$ret['changeFilter'][$lcm['package_id']]['allDistrict'][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret['changeFilter'][$lcm['package_id']]['allDistrict'][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
					}

					if(isset($ret[$lcm['package_id']][$lcm['district']]['all']['all'])){
						if (!in_array($lcm['lcm_no'], $ret[$lcm['package_id']][$lcm['district']]['all']['all'])) {
							$ret[$lcm['package_id']][$lcm['district']]['all']['all'][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret[$lcm['package_id']][$lcm['district']]['all']['all'][] = $lcm['lcm_no'];
					}
					
					if(isset($ret[$lcm['package_id']][$lcm['district']][$lcm['year']]['all'])){
						if (!in_array($lcm['lcm_no'], $ret[$lcm['package_id']][$lcm['district']][$lcm['year']]['all'])) {
							$ret[$lcm['package_id']][$lcm['district']][$lcm['year']]['all'][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret[$lcm['package_id']][$lcm['district']][$lcm['year']]['all'][] = $lcm['lcm_no'];
					}

					if(isset($ret[$lcm['package_id']][$lcm['district']][$lcm['year']][$lcm['month']])){
						if (!in_array($lcm['lcm_no'], $ret[$lcm['package_id']][$lcm['district']][$lcm['year']][$lcm['month']])) {
							$ret[$lcm['package_id']][$lcm['district']][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret[$lcm['package_id']][$lcm['district']][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
					}


					if(isset($ret['changeFilter'][$lcm['package_id']][$lcm['district']][$lcm['year']][$lcm['month']])){
						if (!in_array($lcm['lcm_no'], $ret['changeFilter'][$lcm['package_id']][$lcm['district']][$lcm['year']][$lcm['month']])) {
							$ret['changeFilter'][$lcm['package_id']][$lcm['district']][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
						}
					}
					else{
						$ret['changeFilter'][$lcm['package_id']][$lcm['district']][$lcm['year']][$lcm['month']][] = $lcm['lcm_no'];
					}
					
				}
			}
		}

		return $ret;
	}

	function getDistrictList(){
		$ret = array();
		$districtUrl = 'list_lookupDistrict?d-2647551-fn_package_uuid=';

		if($this->isWPC){
			$res = $this->getCustomDatalistData($districtUrl.$this->currPackageUuid, 'construct');

			if(isset($res['data']) && $res['data']){
				usort($res['data'], function($a, $b) {
					return strcmp($a["district"], $b["district"]);
				});

				foreach ($res['data'] as $lcm) {
					if($lcm['district'] == '') continue;
					$ret['overall']['discFilter'][] = $lcm['district'];
					$ret['changeFilter']['overall']['discFilter'][] = $lcm['district'];
				}
			}
		}

		foreach ($this->childProjectInfo as $childID) {
			$res = $this->getCustomDatalistData($districtUrl.$childID['package_uuid'], 'construct');
			
			if (isset($res['data']) && $res['data']) {
				usort($res['data'], function($a, $b) {
				    return strcmp($a["district"], $b["district"]);
				});

				foreach ($res['data'] as $lcm) {
					if($lcm['district'] == '') continue;
					$ret[$childID['project_id']]['discFilter'][] = $lcm['district'];
					$ret['changeFilter'][$childID['project_id']]['discFilter'][] = $lcm['district'];
				}
			}
		}

		return $ret;
	}

	function getLandInfo(){
		if ($this->project_owner == 'JKR_SABAH') {
			$ret = array(
				"filterLCM" => $this->getLCMNoList(),
				"filterDistrict" => $this->getDistrictList(),
				"summary" => $this->fetchLandSummaryData()
			);
		}else if ($this->project_owner == 'SSLR2') {
			$ret = array(
				"issue" => $this->fetchLandIssueDataSSLR(),
				"encumbrances" => $this->fetchLandEncumbrancesDataSSLR()
			);
		} else {
			$ret = array(
				"issue" => $this->fetchLandIssueData(),
				"encumbrances" => $this->fetchLandEncumbrancesData()
			);
		}

		return $ret;
	}

	function getQAQCInfo(){
		$infoArr = array();
		$processArr = array('MS', 'MOS', 'NCR', 'WIR');
		if ($this->isWPC) {
			$mainRes = $this->getCustomDatalistData('processInfoList?d-1883645-fn_projectID='.$this->projectID);
			if ($mainRes['data']) {
				foreach ($mainRes['data'] as $data) {
					$infoArr[$data['processType']]['overall']['raw'][] = $data;

					// based in month year
					$infoArr[$data['processType']]['overall']['basedOnMonYr'][$data['yr_mon']]['raw'][] = $data;

					// based on month year + status
					$infoArr[$data['processType']]['overall']['basedOnMonYr'][$data['yr_mon']]['basedOnStatus'][$data['status']][] = $data;

					// based on month year + basedOnWd and classification
					if ($data['processType'] == 'NCR') {
						$infoArr[$data['processType']]['overall']['basedOnMonYr'][$data['yr_mon']]['basedOnWD'][$data['ncr_wd']][] = $data;

						$infoArr[$data['processType']]['overall']['basedOnMonYr'][$data['yr_mon']]['basedOnClassif'][$data['c_classification']][] = $data;
					
						// aging (0-30/30-90/>91) - only status not closed
						if ($data['status'] != 'WIR Approved' && $data['status'] != 'Draft') {
							if ($data['aging_day'] < 30) {
								$infoArr[$data['processType']]['overall']['basedOnAging']['<30'][] = $data;
							}elseif ($data['aging_day'] >= 30 && $data['aging_day'] < 90) {
								$infoArr[$data['processType']]['overall']['basedOnAging']['30-90'][] = $data;
							}else{
								$infoArr[$data['processType']]['overall']['basedOnAging']['>90'][] = $data;							}
						}
					}
				}
			}
		}

		// this will be empty if $this->isWPC = true
		// can be optimise by creating one big datalist and just query from there
		foreach ($this->childProjectInfo as $childID) {
			$res = $this->getCustomDatalistData('processInfoList?d-1883645-fn_projectID='.$childID['project_id']);
			if (isset($res['data'])) {
				foreach ($res['data'] as $data) {
					$infoArr[$data['processType']][$childID['project_id']]['raw'][] = $data;
					$infoArr[$data['processType']]['overall']['raw'][] = $data;

					// based in month year
					$infoArr[$data['processType']][$childID['project_id']]['basedOnMonYr'][$data['yr_mon']]['raw'][] = $data;
					$infoArr[$data['processType']]['overall']['basedOnMonYr'][$data['yr_mon']]['raw'][] = $data;

					// based on month year + status
					$infoArr[$data['processType']][$childID['project_id']]['basedOnMonYr'][$data['yr_mon']]['basedOnStatus'][$data['status']][] = $data;
					$infoArr[$data['processType']]['overall']['basedOnMonYr'][$data['yr_mon']]['basedOnStatus'][$data['status']][] = $data;

					// based on month year + basedOnWd and classification
					if ($data['processType'] == 'NCR') {
						$infoArr[$data['processType']][$childID['project_id']]['basedOnMonYr'][$data['yr_mon']]['basedOnWD'][$data['ncr_wd']][] = $data;
						$infoArr[$data['processType']]['overall']['basedOnMonYr'][$data['yr_mon']]['basedOnWD'][$data['ncr_wd']][] = $data;

						$infoArr[$data['processType']][$childID['project_id']]['basedOnMonYr'][$data['yr_mon']]['basedOnClassif'][$data['c_classification']][] = $data;
						$infoArr[$data['processType']]['overall']['basedOnMonYr'][$data['yr_mon']]['basedOnClassif'][$data['c_classification']][] = $data;
					
						// aging (0-30/30-90/>91) - only status not closed
						if ($data['status'] != 'WIR Approved' && $data['status'] != 'Draft') {
							if ($data['aging_day'] < 30) {
								$infoArr[$data['processType']][$childID['project_id']]['basedOnAging']['<30'][] = $data;
								$infoArr[$data['processType']]['overall']['basedOnAging']['<30'][] = $data;
							}elseif ($data['aging_day'] >= 30 && $data['aging_day'] < 90) {
								$infoArr[$data['processType']][$childID['project_id']]['basedOnAging']['30-90'][] = $data;
								$infoArr[$data['processType']]['overall']['basedOnAging']['30-90'][] = $data;
							}else{
								$infoArr[$data['processType']][$childID['project_id']]['basedOnAging']['>90'][] = $data;
								$infoArr[$data['processType']]['overall']['basedOnAging']['>90'][] = $data;							}
						}
					}
				}
			}
		}
		return $infoArr;
	}

