						$info[$val['package_id']][$val['section']]['fatalityCnt'][$year][$monthArray[$month]]['total'] = (isset($info[$val['package_id']][$val['section']]['fatalityCnt'][$year][$monthArray[$month]]['total'])) ? $info[$val['package_id']][$val['section']]['fatalityCnt'][$year][$monthArray[$month]]['total']+$fatality : $fatality;
					
					}
					
				}
			}
		}
		return $info;
	}

