	function fetchMSInfo(){
		$ret = array();

		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_MS', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			// project -> section
			if (isset($res['data']) && $res['data']) {
				usort($res['data'], function ($a, $b) {
				    $t1 = strtotime($a['issued_date']);
				    $t2 = strtotime($b['issued_date']);
				    return $t1 - $t2;
				});
				foreach ($res['data'] as $ms) {
					// based on month and year
					$dateCreated = strtotime($ms['issued_date']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					$ret['overall']['overall']['raw'][] = $ms;
					$ret['overall'][$ms['section']]['raw'][] = $ms;

					// by approval_status
					$approval_status = $ms['approval_status'];
					if(($ms['acknowledge'] != "")){
												
						if($ms['approval_status'] == ""){
							$ms['approval_status'] = "R";
						}
						else if($ms['approval_status'] == "Code 1: Approved"){
							$ms['approval_status'] = "Code 1";
						}
						else if($ms['approval_status'] == "Code 2: Approved with Comments"){
							$ms['approval_status'] = "Code 2";
						}
						else if($ms['approval_status'] == "Code 3: Not Approved and Resubmit"){
							$ms['approval_status'] = "Code 3";
						}

						if (isset($ret['overall']['overall']['byStatus']['all']['all'][$ms['approval_status']])) {
							$ret['overall']['overall']['byStatus']['all']['all'][$ms['approval_status']]++;
						}else{
							$ret['overall']['overall']['byStatus']['all']['all'][$ms['approval_status']] = 1;
						}
						if (isset($ret['overall']['overall']['byStatus'][$year]['all'][$ms['approval_status']])) {
							$ret['overall']['overall']['byStatus'][$year]['all'][$ms['approval_status']]++;
						}else{
							$ret['overall']['overall']['byStatus'][$year]['all'][$ms['approval_status']] = 1;
						}
						if (isset($ret['overall']['overall']['byStatus'][$year][$month][$ms['approval_status']])) {
							$ret['overall']['overall']['byStatus'][$year][$month][$ms['approval_status']]++;
						}else{
							$ret['overall']['overall']['byStatus'][$year][$month][$ms['approval_status']] = 1;
						}

						// by section approval_status
						if (isset($ret['overall'][$ms['section']]['byStatus']['all']['all'][$ms['approval_status']])) {
							$ret['overall'][$ms['section']]['byStatus']['all']['all'][$ms['approval_status']]++;
						}else{
							$ret['overall'][$ms['section']]['byStatus']['all']['all'][$ms['approval_status']] = 1;
						}
						if (isset($ret['overall'][$ms['section']]['byStatus'][$year]['all'][$ms['approval_status']])) {
							$ret['overall'][$ms['section']]['byStatus'][$year]['all'][$ms['approval_status']]++;
						}else{
							$ret['overall'][$ms['section']]['byStatus'][$year]['all'][$ms['approval_status']] = 1;
						}
						if (isset($ret['overall'][$ms['section']]['byStatus'][$year][$month][$ms['approval_status']])) {
							$ret['overall'][$ms['section']]['byStatus'][$year][$month][$ms['approval_status']]++;
						}else{
							$ret['overall'][$ms['section']]['byStatus'][$year][$month][$ms['approval_status']] = 1;
						}
					}
					
					// card
					if (isset($ret['overall']['overall']['card']['cumul']['all']['all'])) {
						$ret['overall']['overall']['card']['cumul']['all']['all']++;
					}else{
						$ret['overall']['overall']['card']['cumul']['all']['all'] = 1;
					}

					if (isset($ret['overall']['overall']['card']['cumulative'][$year]['all'])) {
						$ret['overall']['overall']['card']['cumulative'][$year]['all']++;
					}else{
						$ret['overall']['overall']['card']['cumulative'][$year]['all'] = 1;
					}

					if (isset($ret['overall']['overall']['card']['cumulative'][$year][$month])) {
						$ret['overall']['overall']['card']['cumulative'][$year][$month]++;
					}else{
