					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret[$ms['package_id']][$ms['section']]['byAging'][$year][$month]['less300']++;
					}else{
						$ret[$ms['package_id']][$ms['section']]['byAging'][$year][$month]['more300']++;
					}

					//---------------------END CHILD-----------------------//
				}

				if($res['data']){
					$minDate = strtotime($res['data'][0]['issued_date']);
					$maxDate = strtotime(end($res['data'])['issued_date']);
					$minYear = date("Y", $minDate);
					$now = time();
					if($maxDate > $now){
						$maxYear = date("Y", $maxDate);
					}
					else{
						$maxYear = date("Y", $now);
					}

					$monthHalftext = array("1"=>"Jan","2"=>"Feb","3"=>"Mar","4"=>"Apr","5"=>"May","6"=>"Jun","7"=>"Jul","8"=>"Aug","9"=>"Sep","10"=>"Oct","11"=>"Nov","12"=>"Dec");

					// loop section
					foreach($this->getSectionList() as $package_id => $sections){
						foreach($sections as $section){
							$yDiff = $maxYear - $minYear;
							$yr = $minYear;
							
							$valYrData = 0;
							$valYrSecData = 0;
							$valYrChildData = 0;
							$valYrChildSecData = 0;

							$valYrMthData = 0;
							$valYrMthSecData = 0;
							$valYrMthChildData = 0;
							$valYrMthChildSecData = 0;

							for ($i=0; $i < $yDiff+1 ; $i++) {
								$nYr = $yr++; 
								if (isset($ret['overall']['overall']['card']['cumulative'][$nYr]['all'])) {
									$valYrData = $valYrData + $ret['overall']['overall']['card']['cumulative'][$nYr]['all'];
