								if (isset($ret[$package_id][$section]['card']['cumulative'][$nYr]['all'])) {
									$valYrChildSecData = $valYrChildSecData + $ret[$package_id][$section]['card']['cumulative'][$nYr]['all'];
								}

								$ret['overall']['overall']['card']['cumul'][$nYr]['all'] = $valYrData;
								$ret['overall'][$section]['card']['cumul'][$nYr]['all'] = $valYrSecData;

								$ret[$package_id]['overall']['card']['cumul'][$nYr]['all'] = $valYrChildData;
								$ret[$package_id][$section]['card']['cumul'][$nYr]['all'] =  $valYrChildSecData;

								foreach ($monthHalftext as $key => $mthval) {
									if (isset($ret['overall']['overall']['card']['cumulative'][$nYr][$mthval])) {
										$valYrMthData = $valYrMthData + $ret['overall']['overall']['card']['cumulative'][$nYr][$mthval];
									}
									if (isset($ret['overall'][$section]['card']['cumulative'][$nYr][$mthval])) {
										$valYrMthSecData = $valYrMthSecData + $ret['overall'][$section]['card']['cumulative'][$nYr][$mthval];
									}

									if (isset($ret[$package_id]['overall']['card']['cumulative'][$nYr][$mthval])) {
										$valYrMthChildData = $valYrMthChildData + $ret[$package_id]['overall']['card']['cumulative'][$nYr][$mthval];
									}
		
									if (isset($ret[$package_id][$section]['card']['cumulative'][$nYr][$mthval])) {
										$valYrMthChildSecData = $valYrMthChildSecData + $ret[$package_id][$section]['card']['cumulative'][$nYr][$mthval];
									}

									$ret['overall']['overall']['card']['cumul'][$nYr][$mthval] = $valYrMthData;
