									$ret[$package_id]['overall']['card']['cumul'][$nYr][$mthval] = $valYrMthChildData;
									$ret[$package_id][$section]['card']['cumul'][$nYr][$mthval] =  $valYrMthChildSecData;
								}
							}
						}
					}
				}
			}
		}
		
		return $ret;
	}

	function fetchMSSabahInfo(){
		$ret = array();
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_MS', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			// project -> section
			if (isset($res['data']) && $res['data']) {
				foreach ($res['data'] as $ms) {
					// based on month and year
					$dateCreated = strtotime($ms['issued_date']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					$ret['overall']['raw'][] = $ms;

					// by approval_status
					if($ms['acknowledge'] != ""){

						if(($ms['approval_status'] == "Code B: Accepted with comments" && $ms['require_resubmission'] == "No")|| $ms['approval_status'] == "Code A: Accepted"){
							//for MS Received Card total
							if (isset($ret['overall']['underCard']['all']['all']['plpsCard'])) {
								$ret['overall']['underCard']['all']['all']['plpsCard']++;
							}else{
								$ret['overall']['underCard']['all']['all']['plpsCard'] = 1;
							}
							if (isset($ret['overall']['underCard'][$year]['all']['plpsCard'])) {
								$ret['overall']['underCard'][$year]['all']['plpsCard']++;
							}else{
								$ret['overall']['underCard'][$year]['all']['plpsCard'] = 1;
							}
							if (isset($ret['overall']['underCard'][$year][$month]['plpsCard'])) {
								$ret['overall']['underCard'][$year][$month]['plpsCard']++;
							}else{
								$ret['overall']['underCard'][$year][$month]['plpsCard'] = 1;
							}
						}
						else{
							if (isset($ret['overall']['underCard']['all']['all']['retCard'])) {
								$ret['overall']['underCard']['all']['all']['retCard']++;
							}else{
								$ret['overall']['underCard']['all']['all']['retCard'] = 1;
							}
							if (isset($ret['overall']['underCard'][$year]['all']['retCard'])) {
								$ret['overall']['underCard'][$year]['all']['retCard']++;
							}else{
								$ret['overall']['underCard'][$year]['all']['retCard'] = 1;
							}
							if (isset($ret['overall']['underCard'][$year][$month]['retCard'])) {
								$ret['overall']['underCard'][$year][$month]['retCard']++;
							}else{
								$ret['overall']['underCard'][$year][$month]['retCard'] = 1;
							}
						}

						if($ms['approval_status'] == ""){
							if (isset($ret['overall']['underRevCard']['all']['all']['totalUnderRev'])) {
								$ret['overall']['underRevCard']['all']['all']['totalUnderRev']++;
							}else{
								$ret['overall']['underRevCard']['all']['all']['totalUnderRev'] = 1;
							}
							if (isset($ret['overall']['underRevCard'][$year]['all']['totalUnderRev'])) {
								$ret['overall']['underRevCard'][$year]['all']['totalUnderRev']++;
							}else{
								$ret['overall']['underRevCard'][$year]['all']['totalUnderRev'] = 1;
							}
							if (isset($ret['overall']['underRevCard'][$year][$month]['totalUnderRev'])) {
								$ret['overall']['underRevCard'][$year][$month]['totalUnderRev']++;
							}else{
								$ret['overall']['underRevCard'][$year][$month]['totalUnderRev'] = 1;
							}
						}

						if($ms['approval_status'] == ""){
							$ms['approval_status'] = "Under Review";
						}
						
						if($ms['approval_status'] == "Code A: Accepted"){
							$ms['approval_status'] = "Code A";
						}
						else if($ms['approval_status'] == "Code B: Accepted with comments"){
							$ms['approval_status'] = "Code B";
						}
						else if($ms['approval_status'] == "Code C: Rejected"){
							$ms['approval_status'] = "Code C";
						}

						if (isset($ret['overall']['byStatus']['all']['all'][$ms['approval_status']])) {
							$ret['overall']['byStatus']['all']['all'][$ms['approval_status']]++;
						}else{
							$ret['overall']['byStatus']['all']['all'][$ms['approval_status']] = 1;
						}
						if (isset($ret['overall']['byStatus'][$year]['all'][$ms['approval_status']])) {
							$ret['overall']['byStatus'][$year]['all'][$ms['approval_status']]++;
						}else{
							$ret['overall']['byStatus'][$year]['all'][$ms['approval_status']] = 1;
						}
						if (isset($ret['overall']['byStatus'][$year][$month][$ms['approval_status']])) {
							$ret['overall']['byStatus'][$year][$month][$ms['approval_status']]++;
						}else{
							$ret['overall']['byStatus'][$year][$month][$ms['approval_status']] = 1;
						}
						
					}
					
					// card
					if (isset($ret['overall']['card']['all']['all']['cumulative'])) {
						$ret['overall']['card']['all']['all']['cumulative']++;
					}else{
						$ret['overall']['card']['all']['all']['cumulative'] = 1;
					}
					if (isset($ret['overall']['card'][$year]['all']['cumulative'])) {
						$ret['overall']['card'][$year]['all']['cumulative']++;
					}else{
						$ret['overall']['card'][$year]['all']['cumulative'] = 1;
