	function fetchMAInfoSSLR(){
		$ret = array();

		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_MT', array($this->currPackageUuid, $this->parentProjectId));
			$res = $this->jogetCURL($url);
			// project -> section
			if (isset($res['data']) && $res['data']) {
				usort($res['data'], function ($a, $b) {
					$t1 = strtotime($a['submission_date']);
					$t2 = strtotime($b['submission_date']);
					return $t1 - $t2;
				});
				foreach ($res['data'] as $ma) {
					// based on month and year
					$dateCreated = strtotime($ma['submission_date']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					$ret['overall']['overall']['raw'][] = $ma;
					
					if(($ma['acknowledge'] != "")){
						if(($ma['acknowledge'] != "") && ($ma['approval_code'] == "")){
							$ma['approval_code'] = "R";
						}
						// by status
						if (isset($ret['overall']['overall']['byStatus']['all']['all'][$ma['approval_code']])) {
							$ret['overall']['overall']['byStatus']['all']['all'][$ma['approval_code']]++;
						}else{
							$ret['overall']['overall']['byStatus']['all']['all'][$ma['approval_code']] = 1;
						}
						if (isset($ret['overall']['overall']['byStatus'][$year]['all'][$ma['approval_code']])) {
							$ret['overall']['overall']['byStatus'][$year]['all'][$ma['approval_code']]++;
						}else{
							$ret['overall']['overall']['byStatus'][$year]['all'][$ma['approval_code']] = 1;
						}
						if (isset($ret['overall']['overall']['byStatus'][$year][$month][$ma['approval_code']])) {
							$ret['overall']['overall']['byStatus'][$year][$month][$ma['approval_code']]++;
						}else{
							$ret['overall']['overall']['byStatus'][$year][$month][$ma['approval_code']] = 1;
						}

						// by status for section
						if (isset($ret['overall'][$ma['section']]['byStatus']['all']['all'][$ma['approval_code']])) {
							$ret['overall'][$ma['section']]['byStatus']['all']['all'][$ma['approval_code']]++;
						}else{
							$ret['overall'][$ma['section']]['byStatus']['all']['all'][$ma['approval_code']] = 1;
						}
						if (isset($ret['overall'][$ma['section']]['byStatus'][$year]['all'][$ma['approval_code']])) {
							$ret['overall'][$ma['section']]['byStatus'][$year]['all'][$ma['approval_code']]++;
						}else{
							$ret['overall'][$ma['section']]['byStatus'][$year]['all'][$ma['approval_code']] = 1;
						}
						if (isset($ret['overall'][$ma['section']]['byStatus'][$year][$month][$ma['approval_code']])) {
							$ret['overall'][$ma['section']]['byStatus'][$year][$month][$ma['approval_code']]++;
						}else{
							$ret['overall'][$ma['section']]['byStatus'][$year][$month][$ma['approval_code']] = 1;
						}
					}

					// card
					if (isset($ret['overall']['overall']['card']['cumul']['all']['all'])) {
						$ret['overall']['overall']['card']['cumul']['all']['all']++;
					}else{
						$ret['overall']['overall']['card']['cumul']['all']['all'] = 1;
					}

					if (isset($ret['overall']['overall']['card']['cumulative'][$year]['all'])) {
						$ret['overall']['overall']['card']['cumulative'][$year]['all']++;
					}else{
						$ret['overall']['overall']['card']['cumulative'][$year]['all'] = 1;
					}
					if (isset($ret['overall']['overall']['card']['cumulative'][$year][$month])) {
						$ret['overall']['overall']['card']['cumulative'][$year][$month]++;
					}else{
						$ret['overall']['overall']['card']['cumulative'][$year][$month] = 1;
					}

					//for MA Received Card total
					if (isset($ret['overall']['overall']['cardMA'][$year][$month])) {
						$ret['overall']['overall']['cardMA'][$year][$month]++;
					}else{
