	function fetchMASabahInfo(){
		$ret = array();

		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_MT', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			// project -> section
			if (isset($res['data']) && $res['data']) {
				foreach ($res['data'] as $ma) {
					// based on month and year
					$dateCreated = strtotime($ma['submission_date']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);
					$ret['overall']['raw'][] = $ma;

					if(($ma['acknowledge'] != "")){
						if(($ma['acknowledge'] != "") && ($ma['approval_code'] == "")){
							$ma['approval_code'] = "R";
						}
						// by status
						if (isset($ret['overall']['byStatus']['all']['all'][$ma['approval_code']])) {
							$ret['overall']['byStatus']['all']['all'][$ma['approval_code']]++;
						}else{
							$ret['overall']['byStatus']['all']['all'][$ma['approval_code']] = 1;
						}
						if (isset($ret['overall']['byStatus'][$year]['all'][$ma['approval_code']])) {
							$ret['overall']['byStatus'][$year]['all'][$ma['approval_code']]++;
						}else{
							$ret['overall']['byStatus'][$year]['all'][$ma['approval_code']] = 1;
						}
						if (isset($ret['overall']['byStatus'][$year][$month][$ma['approval_code']])) {
							$ret['overall']['byStatus'][$year][$month][$ma['approval_code']]++;
						}else{
							$ret['overall']['byStatus'][$year][$month][$ma['approval_code']] = 1;
						}
					}

					// card
					if (isset($ret['overall']['card']['all']['all']['cumulative'])) {
						$ret['overall']['card']['all']['all']['cumulative']++;
					}else{
						$ret['overall']['card']['all']['all']['cumulative'] = 1;
					}
					// card
					if (isset($ret['overall']['card'][$year]['all']['cumulative'])) {
						$ret['overall']['card'][$year]['all']['cumulative']++;
					}else{
						$ret['overall']['card'][$year]['all']['cumulative'] = 1;
					}
					// card
					if (isset($ret['overall']['card'][$year][$month]['cumulative'])) {
						$ret['overall']['card'][$year][$month]['cumulative']++;
					}else{
						$ret['overall']['card'][$year][$month]['cumulative'] = 1;
					}

					//for MA Received Card total
					if (isset($ret['overall']['cardMA'][$year][$month])) {
						$ret['overall']['cardMA'][$year][$month]++;
					}else{
						$ret['overall']['cardMA'][$year][$month] = 1;
					}

					// Calculate ageing based on status. Use approval date
					// Trello card for future reference: https://trello.com/c/KRdNOR69/757-sarawak-ageing-of-material-approval-method-statement-in-quality-dashboard
					if (isset($ma['status']) && $ma['status'] == "Closed") {
						$approvalDate = strtotime($ma['date_approved']);
						$diffDays = round(($approvalDate - $dateCreated) / (60 * 60 * 24));
					} else {
						// Count ageing from current date if status is Pending/Open
						$now = new DateTime();
						$diffDays = round(($now->getTimestamp()-$dateCreated) / (60 * 60 * 24));
					}
					
					if (!isset($ret['overall']['byAging']['all']['all']['less100'])) {
						$ret['overall']['byAging']['all']['all']['less100'] = 0;
					}
					if (!isset($ret['overall']['byAging']['all']['all']['less300'])) {
						$ret['overall']['byAging']['all']['all']['less300'] = 0;
					}
					if (!isset($ret['overall']['byAging']['all']['all']['more300'])) {
						$ret['overall']['byAging']['all']['all']['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret['overall']['byAging']['all']['all']['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret['overall']['byAging']['all']['all']['less300']++;
					}else{
						$ret['overall']['byAging']['all']['all']['more300']++;
					}

					if (!isset($ret['overall']['byAging'][$year]['all']['less100'])) {
						$ret['overall']['byAging'][$year]['all']['less100'] = 0;
					}
					if (!isset($ret['overall']['byAging'][$year]['all']['less300'])) {
						$ret['overall']['byAging'][$year]['all']['less300'] = 0;
					}
					if (!isset($ret['overall']['byAging'][$year]['all']['more300'])) {
						$ret['overall']['byAging'][$year]['all']['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret['overall']['byAging'][$year]['all']['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret['overall']['byAging'][$year]['all']['less300']++;
					}else{
						$ret['overall']['byAging'][$year]['all']['more300']++;
					}

					if (!isset($ret['overall']['byAging'][$year][$month]['less100'])) {
						$ret['overall']['byAging'][$year][$month]['less100'] = 0;
					}
					if (!isset($ret['overall']['byAging'][$year][$month]['less300'])) {
						$ret['overall']['byAging'][$year][$month]['less300'] = 0;
					}
					if (!isset($ret['overall']['byAging'][$year][$month]['more300'])) {
						$ret['overall']['byAging'][$year][$month]['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret['overall']['byAging'][$year][$month]['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret['overall']['byAging'][$year][$month]['less300']++;
					}else{
						$ret['overall']['byAging'][$year][$month]['more300']++;
					}

				}
			}
		}
		else{
			$url = $this->jogetLinkObj->getLink('dash_cons_MT', array('', $this->projectID));
			$res = $this->jogetCURL($url);
			if (isset($res['data']) && $res['data']) {
				foreach ($res['data'] as $ma) {
					// based on month and year
					$dateCreated = strtotime($ma['submission_date']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);
					$ret['overall']['raw'][] = $ma;

					if(($ma['acknowledge'] != "")){
						if(($ma['acknowledge'] != "") && ($ma['approval_code'] == "")){
							$ma['approval_code'] = "R";
						}
						// by status
						if (isset($ret['overall']['byStatus']['all']['all'][$ma['approval_code']])) {
							$ret['overall']['byStatus']['all']['all'][$ma['approval_code']]++;
						}else{
							$ret['overall']['byStatus']['all']['all'][$ma['approval_code']] = 1;
						}
						if (isset($ret['overall']['byStatus'][$year]['all'][$ma['approval_code']])) {
							$ret['overall']['byStatus'][$year]['all'][$ma['approval_code']]++;
						}else{
							$ret['overall']['byStatus'][$year]['all'][$ma['approval_code']] = 1;
						}
						if (isset($ret['overall']['byStatus'][$year][$month][$ma['approval_code']])) {
							$ret['overall']['byStatus'][$year][$month][$ma['approval_code']]++;
						}else{
							$ret['overall']['byStatus'][$year][$month][$ma['approval_code']] = 1;
						}

						//---------------START CHILD----------------//
						if (isset($ret[$ma['package_id']]['byStatus']['all']['all'][$ma['approval_code']])) {
							$ret[$ma['package_id']]['byStatus']['all']['all'][$ma['approval_code']]++;
						}else{
							$ret[$ma['package_id']]['byStatus']['all']['all'][$ma['approval_code']] = 1;
						}
						if (isset($ret[$ma['package_id']]['byStatus'][$year]['all'][$ma['approval_code']])) {
							$ret[$ma['package_id']]['byStatus'][$year]['all'][$ma['approval_code']]++;
						}else{
							$ret[$ma['package_id']]['byStatus'][$year]['all'][$ma['approval_code']] = 1;
						}
						if (isset($ret[$ma['package_id']]['byStatus'][$year][$month][$ma['approval_code']])) {
							$ret[$ma['package_id']]['byStatus'][$year][$month][$ma['approval_code']]++;
						}else{
							$ret[$ma['package_id']]['byStatus'][$year][$month][$ma['approval_code']] = 1;
						}
						//---------------END CHILD----------------//
					}

					// card
					if (isset($ret['overall']['card']['all']['all']['cumulative'])) {
						$ret['overall']['card']['all']['all']['cumulative']++;
					}else{
						$ret['overall']['card']['all']['all']['cumulative'] = 1;
					}
					// card
					if (isset($ret['overall']['card'][$year]['all']['cumulative'])) {
						$ret['overall']['card'][$year]['all']['cumulative']++;
					}else{
						$ret['overall']['card'][$year]['all']['cumulative'] = 1;
					}
					// card
					if (isset($ret['overall']['card'][$year][$month]['cumulative'])) {
						$ret['overall']['card'][$year][$month]['cumulative']++;
					}else{
						$ret['overall']['card'][$year][$month]['cumulative'] = 1;
					}

					//---------------START CHILD----------------//
					if (isset($ret[$ma['package_id']]['card']['all']['all']['cumulative'])) {
						$ret[$ma['package_id']]['card']['all']['all']['cumulative']++;
					}else{
						$ret[$ma['package_id']]['card']['all']['all']['cumulative'] = 1;
					}
					// card
					if (isset($ret[$ma['package_id']]['card'][$year]['all']['cumulative'])) {
						$ret[$ma['package_id']]['card'][$year]['all']['cumulative']++;
					}else{
						$ret[$ma['package_id']]['card'][$year]['all']['cumulative'] = 1;
					}
					// card
					if (isset($ret[$ma['package_id']]['card'][$year][$month]['cumulative'])) {
						$ret[$ma['package_id']]['card'][$year][$month]['cumulative']++;
					}else{
						$ret[$ma['package_id']]['card'][$year][$month]['cumulative'] = 1;
					}
					//---------------END CHILD----------------//

					//for MA Received Card total
					if (isset($ret['overall']['cardMA'][$year][$month])) {
						$ret['overall']['cardMA'][$year][$month]++;
					}else{
						$ret['overall']['cardMA'][$year][$month] = 1;
					}

					//---------------START CHILD----------------//
					if (isset($ret[$ma['package_id']]['cardMA'][$year][$month])) {
						$ret[$ma['package_id']]['cardMA'][$year][$month]++;
					}else{
						$ret[$ma['package_id']]['cardMA'][$year][$month] = 1;
					}
					//---------------END CHILD----------------//

					// Calculate ageing based on status. Use approval date
					// Trello card for future reference: https://trello.com/c/KRdNOR69/757-sarawak-ageing-of-material-approval-method-statement-in-quality-dashboard
					if (isset($ma['status']) && $ma['status'] == "Closed") {
						$approvalDate = strtotime($ma['date_approved']);
						$diffDays = round(($approvalDate - $dateCreated) / (60 * 60 * 24));
					} else {
						// Count ageing from current date if status is Pending/Open
						$now = new DateTime();
						$diffDays = round(($now->getTimestamp()-$dateCreated) / (60 * 60 * 24));
					}
					
					if (!isset($ret['overall']['byAging']['all']['all']['less100'])) {
						$ret['overall']['byAging']['all']['all']['less100'] = 0;
					}
					if (!isset($ret['overall']['byAging']['all']['all']['less300'])) {
						$ret['overall']['byAging']['all']['all']['less300'] = 0;
					}
					if (!isset($ret['overall']['byAging']['all']['all']['more300'])) {
						$ret['overall']['byAging']['all']['all']['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret['overall']['byAging']['all']['all']['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret['overall']['byAging']['all']['all']['less300']++;
					}else{
						$ret['overall']['byAging']['all']['all']['more300']++;
					}

					if (!isset($ret['overall']['byAging'][$year]['all']['less100'])) {
						$ret['overall']['byAging'][$year]['all']['less100'] = 0;
					}
					if (!isset($ret['overall']['byAging'][$year]['all']['less300'])) {
						$ret['overall']['byAging'][$year]['all']['less300'] = 0;
					}
					if (!isset($ret['overall']['byAging'][$year]['all']['more300'])) {
						$ret['overall']['byAging'][$year]['all']['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret['overall']['byAging'][$year]['all']['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret['overall']['byAging'][$year]['all']['less300']++;
					}else{
						$ret['overall']['byAging'][$year]['all']['more300']++;
					}

					if (!isset($ret['overall']['byAging'][$year][$month]['less100'])) {
						$ret['overall']['byAging'][$year][$month]['less100'] = 0;
					}
					if (!isset($ret['overall']['byAging'][$year][$month]['less300'])) {
						$ret['overall']['byAging'][$year][$month]['less300'] = 0;
					}
					if (!isset($ret['overall']['byAging'][$year][$month]['more300'])) {
						$ret['overall']['byAging'][$year][$month]['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret['overall']['byAging'][$year][$month]['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret['overall']['byAging'][$year][$month]['less300']++;
					}else{
						$ret['overall']['byAging'][$year][$month]['more300']++;
					}

					//--------------START CHILD-----------------//
					if (!isset($ret[$ma['package_id']]['byAging']['all']['all']['less100'])) {
						$ret[$ma['package_id']]['byAging']['all']['all']['less100'] = 0;
					}
					if (!isset($ret[$ma['package_id']]['byAging']['all']['all']['less300'])) {
						$ret[$ma['package_id']]['byAging']['all']['all']['less300'] = 0;
					}
					if (!isset($ret[$ma['package_id']]['byAging']['all']['all']['more300'])) {
						$ret[$ma['package_id']]['byAging']['all']['all']['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret[$ma['package_id']]['byAging']['all']['all']['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret[$ma['package_id']]['byAging']['all']['all']['less300']++;
					}else{
						$ret[$ma['package_id']]['byAging']['all']['all']['more300']++;
					}

					if (!isset($ret[$ma['package_id']]['byAging'][$year]['all']['less100'])) {
						$ret[$ma['package_id']]['byAging'][$year]['all']['less100'] = 0;
					}
					if (!isset($ret[$ma['package_id']]['byAging'][$year]['all']['less300'])) {
						$ret[$ma['package_id']]['byAging'][$year]['all']['less300'] = 0;
					}
					if (!isset($ret[$ma['package_id']]['byAging'][$year]['all']['more300'])) {
						$ret[$ma['package_id']]['byAging'][$year]['all']['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret[$ma['package_id']]['byAging'][$year]['all']['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret[$ma['package_id']]['byAging'][$year]['all']['less300']++;
					}else{
						$ret[$ma['package_id']]['byAging'][$year]['all']['more300']++;
					}

					if (!isset($ret[$ma['package_id']]['byAging'][$year][$month]['less100'])) {
						$ret[$ma['package_id']]['byAging'][$year][$month]['less100'] = 0;
					}
					if (!isset($ret[$ma['package_id']]['byAging'][$year][$month]['less300'])) {
						$ret[$ma['package_id']]['byAging'][$year][$month]['less300'] = 0;
					}
					if (!isset($ret[$ma['package_id']]['byAging'][$year][$month]['more300'])) {
						$ret[$ma['package_id']]['byAging'][$year][$month]['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret[$ma['package_id']]['byAging'][$year][$month]['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret[$ma['package_id']]['byAging'][$year][$month]['less300']++;
					}else{
						$ret[$ma['package_id']]['byAging'][$year][$month]['more300']++;
					}
					//--------------END CHILD-------------------//

				}
			}
		}

		return $ret;	
	}

	function fetchRFIInfo($urw_flag = false){
		$ret = array();
		$rfi_link = "dash_cons_RFI";
		if ($urw_flag){
			$rfi_link = 'dash_cons_RFI_urw';
		}
		
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink($rfi_link, array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			$this->rfiDataAPI = $res;
			if (isset($res['data']) && $res['data']) {
				// usort($res['data'], function ($a, $b) {
				// 	$t1 = strtotime($a['date_request']);
				// 	$t2 = strtotime($b['date_request']);
				// 	return $t1 - $t2;
				// });
				foreach ($res['data'] as $rfi) {

					if($this->project_owner == "JKR_SABAH"){

						// based on month and year
						$dateCreated = strtotime($rfi['dateCreated']);
						$year = date("Y", $dateCreated);
						$month = date("M", $dateCreated);

						if($rfi['work_discipline'] == 'Utilities Relocation Work'){
							$ret['overall']['overall']['all']['all']['raw'][] = $rfi;
							$ret['overall']['overall'][$year]['all']['raw'][] = $rfi;
							$ret['overall']['overall'][$year][$month]['raw'][] = $rfi;


							// card
							if (isset($ret['overall']['overall']['card']['all']['all']['cumulative'])) {
								$ret['overall']['overall']['card']['all']['all']['cumulative']++;
							}else{
								$ret['overall']['overall']['card']['all']['all']['cumulative'] = 1;
							}
							if (isset($ret['overall']['overall']['card'][$year]['all']['cumulative'])) {
								$ret['overall']['overall']['card'][$year]['all']['cumulative']++;
							}else{
								$ret['overall']['overall']['card'][$year]['all']['cumulative'] = 1;
							}
							if (isset($ret['overall']['overall']['card'][$year][$month]['cumulative'])) {
								$ret['overall']['overall']['card'][$year][$month]['cumulative']++;
							}else{
								$ret['overall']['overall']['card'][$year][$month]['cumulative'] = 1;
							}

							//card by status
							$rfi['status'] = ($rfi['status'] == 'Closed') ? "Closed" : "Open";
							if (isset($ret['overall']['overall']['card']['all']['all'][$rfi['status']])) {
								$ret['overall']['overall']['card']['all']['all'][$rfi['status']]++;
							}else{
								$ret['overall']['overall']['card']['all']['all'][$rfi['status']] = 1;
							}
							if (isset($ret['overall']['overall']['card'][$year]['all'][$rfi['status']])) {
								$ret['overall']['overall']['card'][$year]['all'][$rfi['status']]++;
							}else{
								$ret['overall']['overall']['card'][$year]['all'][$rfi['status']] = 1;
							}
							if (isset($ret['overall']['overall']['card'][$year][$month][$rfi['status']])) {
								$ret['overall']['overall']['card'][$year][$month][$rfi['status']]++;
							}else{
								$ret['overall']['overall']['card'][$year][$month][$rfi['status']] = 1;
							}

						}

					}
					else{

						// based on month and year
						$dateCreated = strtotime($rfi['date_request']);
						$year = date("Y", $dateCreated);
						$month = date("M", $dateCreated);
						
						//need to get only current month
						$dateCheck = strtotime(date('01-m-Y'));
						$yearCurrent = date("Y", $dateCheck);
						$monthCurrent = date("M", $dateCheck);

						$ret['overall']['overall']['raw'][] = $rfi;

						// card
						if (isset($ret['overall']['overall']['card']['all']['all']['cumul'])) {
							$ret['overall']['overall']['card']['all']['all']['cumul']++;
						}else{
							$ret['overall']['overall']['card']['all']['all']['cumul'] = 1;
						}
						if (isset($ret['overall']['overall']['card'][$year]['all']['cumulative'])) {
							$ret['overall']['overall']['card'][$year]['all']['cumulative']++;
						}else{
							$ret['overall']['overall']['card'][$year]['all']['cumulative'] = 1;
						}
						if (isset($ret['overall']['overall']['card'][$year][$month]['cumulative'])) {
							$ret['overall']['overall']['card'][$year][$month]['cumulative']++;
						}else{
							$ret['overall']['overall']['card'][$year][$month]['cumulative'] = 1;
						}

						// card based on SECTION
						if (isset($ret['overall'][$rfi['section']]['card']['all']['all']['cumul'])) {
							$ret['overall'][$rfi['section']]['card']['all']['all']['cumul']++;
						}else{
							$ret['overall'][$rfi['section']]['card']['all']['all']['cumul'] = 1;
						}
						if (isset($ret['overall'][$rfi['section']]['card'][$year]['all']['cumulative'])) {
							$ret['overall'][$rfi['section']]['card'][$year]['all']['cumulative']++;
						}else{
							$ret['overall'][$rfi['section']]['card'][$year]['all']['cumulative'] = 1;
						}
						if (isset($ret['overall'][$rfi['section']]['card'][$year][$month]['cumulative'])) {
							$ret['overall'][$rfi['section']]['card'][$year][$month]['cumulative']++;
						}else{
							$ret['overall'][$rfi['section']]['card'][$year][$month]['cumulative'] = 1;
						}
					
						$status = ($rfi['rfi_acknowledge'] == 'True') ? "replied" : "remaining";
						if (isset($ret['overall']['overall']['card']['all']['all'][$status]['cumul'])) {
							$ret['overall']['overall']['card']['all']['all'][$status]['cumul']++;
						}else{
							$ret['overall']['overall']['card']['all']['all'][$status]['cumul'] = 1;
						}
						if (isset($ret['overall']['overall']['card'][$year]['all'][$status]['cumulative'])) {
							$ret['overall']['overall']['card'][$year]['all'][$status]['cumulative']++;
						}else{
							$ret['overall']['overall']['card'][$year]['all'][$status]['cumulative'] = 1;
						}
						if (isset($ret['overall']['overall']['card'][$year][$month][$status]['cumulative'])) {
							$ret['overall']['overall']['card'][$year][$month][$status]['cumulative']++;
						}else{
							$ret['overall']['overall']['card'][$year][$month][$status]['cumulative'] = 1;
						}
					
						if (isset($ret['overall'][$rfi['section']]['card']['all']['all'][$status]['cumul'])) {
							$ret['overall'][$rfi['section']]['card']['all']['all'][$status]['cumul']++;
						}else{
							$ret['overall'][$rfi['section']]['card']['all']['all'][$status]['cumul'] = 1;
						}
						if (isset($ret['overall'][$rfi['section']]['card'][$year]['all'][$status]['cumulative'])) {
							$ret['overall'][$rfi['section']]['card'][$year]['all'][$status]['cumulative']++;
						}else{
							$ret['overall'][$rfi['section']]['card'][$year]['all'][$status]['cumulative'] = 1;
						}
						if (isset($ret['overall'][$rfi['section']]['card'][$year][$month][$status]['cumulative'])) {
							$ret['overall'][$rfi['section']]['card'][$year][$month][$status]['cumulative']++;
						}else{
							$ret['overall'][$rfi['section']]['card'][$year][$month][$status]['cumulative'] = 1;
						}
						
						if (($year == $yearCurrent) && ($month == $monthCurrent)){
							// card for current year & month
							if (isset($ret['overall']['overall']['card']['all']['all']['current'])) {
								$ret['overall']['overall']['card']['all']['all']['current']++;
							}else{
								$ret['overall']['overall']['card']['all']['all']['current'] = 1;
							}

							if (isset($ret['overall'][$rfi['section']]['card']['all']['all']['current'])) {
								$ret['overall'][$rfi['section']]['card']['all']['all']['current']++;
							}else{
								$ret['overall'][$rfi['section']]['card']['all']['all']['current'] = 1;
							}

						}
						if (isset($ret['overall']['overall']['card'][$year]['all']['current'])) {
							$ret['overall']['overall']['card'][$year]['all']['current']++;
						}else{
							$ret['overall']['overall']['card'][$year]['all']['current'] = 1;
						}
						if (isset($ret['overall']['overall']['card'][$year][$month]['current'])) {
							$ret['overall']['overall']['card'][$year][$month]['current']++;
						}else{
							$ret['overall']['overall']['card'][$year][$month]['current'] = 1;
						}
						if (isset($ret['overall'][$rfi['section']]['card'][$year]['all']['current'])) {
							$ret['overall'][$rfi['section']]['card'][$year]['all']['current']++;
						}else{
							$ret['overall'][$rfi['section']]['card'][$year]['all']['current'] = 1;
						}
						if (isset($ret['overall'][$rfi['section']]['card'][$year][$month]['current'])) {
							$ret['overall'][$rfi['section']]['card'][$year][$month]['current']++;
						}else{
							$ret['overall'][$rfi['section']]['card'][$year][$month]['current'] = 1;
						}
					}
				}

				if($res['data'] && $this->project_owner == "JKR_SARAWAK"){
					$minDate = strtotime($res['data'][0]['date_request']);
					$maxDate = strtotime(end($res['data'])['date_request']);
					$minYear = date("Y", $minDate);
					$now = time();
					if($maxDate > $now){
						$maxYear = date("Y", $maxDate);
					}
					else{
						$maxYear = date("Y", $now);
					}

					$monthHalftext = array("1"=>"Jan","2"=>"Feb","3"=>"Mar","4"=>"Apr","5"=>"May","6"=>"Jun","7"=>"Jul","8"=>"Aug","9"=>"Sep","10"=>"Oct","11"=>"Nov","12"=>"Dec");

					foreach($this->getSectionList()['overall'] as $section){
						$yDiff = $maxYear - $minYear;
						$yr = $minYear;
						
						$valYrData = 0;
						$valYrSecData = 0;
						$valYrStatusData = 0;
						$valYrSecStatusData = 0;
						$valYrStatusRemData = 0;
						$valYrSecStatusRemData = 0;

						$valMthData = 0;
						$valMthSecData = 0;
						$valMthStatusData = 0;
						$valMthSecStatusData = 0;
						$valMthSecStatusRemData = 0;
						$valYrMthStatusRemData = 0;
						$valYrMthSecStatusRemData = 0;

						for ($i=0; $i < $yDiff+1 ; $i++) {
							$nYr = $yr++; 

							if (isset($ret['overall']['overall']['card'][$nYr]['all']['cumulative'])) {
								$valYrData = $valYrData + $ret['overall']['overall']['card'][$nYr]['all']['cumulative'];
							}
							if (isset($ret['overall'][$section]['card'][$nYr]['all']['cumulative'])) {
								$valYrSecData = $valYrSecData + $ret['overall'][$section]['card'][$nYr]['all']['cumulative'];
							}

							if (isset($ret['overall']['overall']['card'][$nYr]['all']['replied']['cumulative'])) {
								$valYrStatusData = $valYrStatusData + $ret['overall']['overall']['card'][$nYr]['all']['replied']['cumulative'];
							}
							if (isset($ret['overall'][$section]['card'][$nYr]['all']['replied']['cumulative'])) {
								$valYrSecStatusData = $valYrSecStatusData + $ret['overall'][$section]['card'][$nYr]['all']['replied']['cumulative'];
							}
							
							if (isset($ret['overall']['overall']['card'][$nYr]['all']['remaining']['cumulative'])) {
								$valYrStatusRemData = $valYrStatusRemData + $ret['overall']['overall']['card'][$nYr]['all']['remaining']['cumulative'];
							}
							if (isset($ret['overall'][$section]['card'][$nYr]['all']['remaining']['cumulative'])) {
								$valYrSecStatusRemData = $valYrSecStatusRemData + $ret['overall'][$section]['card'][$nYr]['all']['remaining']['cumulative'];
							}

							$ret['overall']['overall']['card'][$nYr]['all']['cumul'] = $valYrData;
							$ret['overall'][$section]['card'][$nYr]['all']['cumul'] = $valYrSecData;

							$ret['overall']['overall']['card'][$nYr]['all']['replied']['cumul'] = $valYrStatusData;
							$ret['overall'][$section]['card'][$nYr]['all']['replied']['cumul'] = $valYrSecStatusData;
							
							$ret['overall']['overall']['card'][$nYr]['all']['remaining']['cumul'] = $valYrStatusRemData;
							$ret['overall'][$section]['card'][$nYr]['all']['remaining']['cumul'] = $valYrSecStatusRemData;
							
