	function fetchRFITInfo(){
		$ret = array();
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_RFIT', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			if (isset($res['data']) && $res['data']) {

				usort($res['data'], function($a, $b) {
					return strtotime($a['date_request']) - strtotime($b['date_request']);
				});
				
				$cumulativeMonth = 1;
				foreach ($res['data'] as $rfi) {
					// based on month and year
					$dateCreated = strtotime($rfi['dateCreated']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					//need to get only current month
					$dateCheck = strtotime(date('01-m-Y'));
					$yearCurrent = date("Y", $dateCheck);
					$monthCurrent = date("M", $dateCheck);

					if($year == $yearCurrent && $month == $monthCurrent){
						// card for current year & month
						if (isset($ret['overall']['card']['all']['all']['rfitTotal'])) {
							$ret['overall']['card']['all']['all']['rfitTotal']++;
						}else{
							$ret['overall']['card']['all']['all']['rfitTotal'] = 1;
						}
					}
					if (isset($ret['overall']['card'][$year]['all']['rfitTotal'])) {
						$ret['overall']['card'][$year]['all']['rfitTotal']++;
					}else{
						$ret['overall']['card'][$year]['all']['rfitTotal'] = 1;
					}
					if (isset($ret['overall']['card'][$year][$month]['rfitTotal'])) {
						$ret['overall']['card'][$year][$month]['rfitTotal']++;
					}else{
						$ret['overall']['card'][$year][$month]['rfitTotal'] = 1;
					}

					//card for cumulative rfi
					$ret['overall']['card']['all']['all']['cumulTotal'] = $cumulativeMonth;
					$ret['overall']['card'][$year]['all']['cumulTotal'] = $cumulativeMonth;
					$ret['overall']['card'][$year][$month]['cumulTotal'] = $cumulativeMonth;

					$rfi['status'] = ($rfi['rfi_acknowledge'] == "True") ? "replied" : "remaining";
					if (isset($ret['overall']['card']['all']['all'][$rfi['status']])) {
						$ret['overall']['card']['all']['all'][$rfi['status']]++;
					}else{
						$ret['overall']['card']['all']['all'][$rfi['status']] = 1;
					}
					if (isset($ret['overall']['card'][$year]['all'][$rfi['status']])) {
						$ret['overall']['card'][$year]['all'][$rfi['status']]++;
					}else{
						$ret['overall']['card'][$year]['all'][$rfi['status']] = 1;
					}
					if (isset($ret['overall']['card'][$year][$month][$rfi['status']])) {
						$ret['overall']['card'][$year][$month][$rfi['status']]++;
					}else{
						$ret['overall']['card'][$year][$month][$rfi['status']] = 1;
					}

					// aging
					$now = new DateTime();
					$dateAcknowledge = strtotime($rfi['acknowledged_date']);
					$diffDays = round(($now->getTimestamp()-$dateAcknowledge) / (60 * 60 * 24));

					if (!isset($ret['overall']['all']['all']['byAging']['less100'])) {
						$ret['overall']['all']['all']['byAging']['less100'] = 0;
					}
					if (!isset($ret['overall']['all']['all']['byAging']['less300'])) {
						$ret['overall']['all']['all']['byAging']['less300'] = 0;
					}
					if (!isset($ret['overall']['all']['all']['byAging']['more300'])) {
						$ret['overall']['all']['all']['byAging']['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret['overall']['all']['all']['byAging']['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret['overall']['all']['all']['byAging']['less300']++;
					}else{
						$ret['overall']['all']['all']['byAging']['more300']++;
					}

					if (!isset($ret['overall'][$year]['all']['byAging']['less100'])) {
						$ret['overall'][$year]['all']['byAging']['less100'] = 0;
					}
					if (!isset($ret['overall'][$year]['all']['byAging']['less300'])) {
						$ret['overall'][$year]['all']['byAging']['less300'] = 0;
					}
					if (!isset($ret['overall'][$year]['all']['byAging']['more300'])) {
						$ret['overall'][$year]['all']['byAging']['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret['overall'][$year]['all']['byAging']['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret['overall'][$year]['all']['byAging']['less300']++;
					}else{
						$ret['overall'][$year]['all']['byAging']['more300']++;
					}

					if (!isset($ret['overall'][$year][$month]['byAging']['less100'])) {
						$ret['overall'][$year][$month]['byAging']['less100'] = 0;
					}
					if (!isset($ret['overall'][$year][$month]['byAging']['less300'])) {
						$ret['overall'][$year][$month]['byAging']['less300'] = 0;
					}
					if (!isset($ret['overall'][$year][$month]['byAging']['more300'])) {
						$ret['overall'][$year][$month]['byAging']['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret['overall'][$year][$month]['byAging']['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret['overall'][$year][$month]['byAging']['less300']++;
					}else{
						$ret['overall'][$year][$month]['byAging']['more300']++;
					}

					$cumulativeMonth++;
				}
			}
		}
		else{
			$url = $this->jogetLinkObj->getLink('dash_cons_RFIT', array('', $this->projectID));
			$res = $this->jogetCURL($url);
			if (isset($res['data']) && $res['data']) {
				usort($res['data'], function($a, $b) {
					return strtotime($a['date_request']) - strtotime($b['date_request']);
				});
				
				$cumulativeMonth = 1;
				foreach ($res['data'] as $rfi) {
					if (!isset($cumulativeMonthChild[$rfi['package_id']])) $cumulativeMonthChild[$rfi['package_id']] = 1;
					// based on month and year
					$dateCreated = strtotime($rfi['dateCreated']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					//need to get only current month
					$dateCheck = strtotime(date('01-m-Y'));
					$yearCurrent = date("Y", $dateCheck);
					$monthCurrent = date("M", $dateCheck);

					if($year == $yearCurrent && $month == $monthCurrent){
						// card for current year & month
						if (isset($ret['overall']['card']['all']['all']['rfitTotal'])) {
							$ret['overall']['card']['all']['all']['rfitTotal']++;
						}else{
							$ret['overall']['card']['all']['all']['rfitTotal'] = 1;
						}

						//---------------START CHILD----------------//
						if (isset($ret[$rfi['package_id']]['card']['all']['all']['rfitTotal'])) {
							$ret[$rfi['package_id']]['card']['all']['all']['rfitTotal']++;
						}else{
