					$ret[$rfi['package_id']]['card'][$year]['all']['cumulTotal'] = $cumulativeMonthChild[$rfi['package_id']];
					$ret[$rfi['package_id']]['card'][$year][$month]['cumulTotal'] = $cumulativeMonthChild[$rfi['package_id']];
