	function getNCRSabahdata(){
		$ret = array();
		
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_NCR', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			if (isset($res['data']) && $res['data']) {
				foreach ($res['data'] as $ncr) {
					// based on month and year
					$dateCreated = strtotime($ncr['date_issued']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					//for NCR Received Card total
					if (isset($ret['overall']['cardNCR'][$year][$month])) {
						$ret['overall']['cardNCR'][$year][$month]++;
					}else{
						$ret['overall']['cardNCR'][$year][$month] = 1;
					}

					// ncr Quality - status
					$ncr['status'] = ($ncr['status'] == 'Pending') ? "Open" : "Closed";
					if (strtolower($ncr['type']) == "quality") {
						if (isset($ret['overall']['qualityStatus']['all']['all'][$ncr['status']])) {
							$ret['overall']['qualityStatus']['all']['all'][$ncr['status']]++;
						}else{
							$ret['overall']['qualityStatus']['all']['all'][$ncr['status']] = 1;
						}
						if (isset($ret['overall']['qualityStatus'][$year]['all'][$ncr['status']])) {
							$ret['overall']['qualityStatus'][$year]['all'][$ncr['status']]++;
						}else{
							$ret['overall']['qualityStatus'][$year]['all'][$ncr['status']] = 1;
						}
						if (isset($ret['overall']['qualityStatus'][$year][$month][$ncr['status']])) {
							$ret['overall']['qualityStatus'][$year][$month][$ncr['status']]++;
						}else{
							$ret['overall']['qualityStatus'][$year][$month][$ncr['status']] = 1;
						}
					}

					// ncr Health & Safety - status
					if (strtolower($ncr['type']) == "health & safety" || strtolower($ncr['type']) == "environment" || strtolower($ncr['type']) == "traffic") {
						if (isset($ret['overall']['hseStatus']['all']['all'][$ncr['status']])) {
							$ret['overall']['hseStatus']['all']['all'][$ncr['status']]++;
						}else{
							$ret['overall']['hseStatus']['all']['all'][$ncr['status']] = 1;
						}
						if (isset($ret['overall']['hseStatus'][$year]['all'][$ncr['status']])) {
							$ret['overall']['hseStatus'][$year]['all'][$ncr['status']]++;
						}else{
							$ret['overall']['hseStatus'][$year]['all'][$ncr['status']] = 1;
						}
						if (isset($ret['overall']['hseStatus'][$year][$month][$ncr['status']])) {
							$ret['overall']['hseStatus'][$year][$month][$ncr['status']]++;
						}else{
							$ret['overall']['hseStatus'][$year][$month][$ncr['status']] = 1;
						}

					}

					if (isset($ret['overall']['table']['all']['all'][$ncr['work_discipline']]['received'])) {
						$ret['overall']['table']['all']['all'][$ncr['work_discipline']]['received']++;
					}else{
						$ret['overall']['table']['all']['all'][$ncr['work_discipline']]['received'] = 1;
					}						
					if (isset($ret['overall']['table'][$year]['all'][$ncr['work_discipline']]['received'])) {
