	function getNCRdataSSLR(){
		$ret = array();
		
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_NCR', array($this->currPackageUuid, $this->parentProjectId));
			$res = $this->jogetCURL($url);
			
			if (isset($res['data']) && $res['data']) {
				foreach ($res['data'] as $ncr) {
					// based on month and year
					$dateCreated = strtotime($ncr['date_issued']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					//for NCR Received Card total
					if (isset($ret['overall']['overall']['cardNCR'][$year][$month])) {
						$ret['overall']['overall']['cardNCR'][$year][$month]++;
					}else{
						$ret['overall']['overall']['cardNCR'][$year][$month] = 1;
					}
					
					//for NCR Received Card total ----- BASED ON SECTION
					if (isset($ret['overall'][$ncr['section']]['cardNCR'][$year][$month])) {
						$ret['overall'][$ncr['section']]['cardNCR'][$year][$month]++;
					}else{
						$ret['overall'][$ncr['section']]['cardNCR'][$year][$month] = 1;
