						$ret[$ncr['package_id']][$ncr['section']]['byAging'][$year][$month]['more300'] = 0;
					}

					if ($diffDays < 100) {
						$ret[$ncr['package_id']][$ncr['section']]['byAging'][$year][$month]['less100']++;
					}else if ($diffDays >= 100 && $diffDays <= 300){
						$ret[$ncr['package_id']][$ncr['section']]['byAging'][$year][$month]['less300']++;
					}else{
						$ret[$ncr['package_id']][$ncr['section']]['byAging'][$year][$month]['more300']++;
					}
					//-----------------------END CHILD--------------------//
				}
			}
		}

		return $ret;
	}

