	function getQualityInfo(){
		$ret = array();
		$urw_flag = false;
		if ($this->project_owner == "JKR_SABAH"){
			$ret['sd'] = $this->fetchSDInfo();
			$ret['ma'] = $this->fetchMASabahInfo();
			$ret['ms'] = $this->fetchMSSabahInfo();
			$ret['ncr'] = $this->getNCRSabahdata();
			$ret['rfit'] = $this->fetchRFITInfo();
			$ret['rfi'] = $this->fetchRFISabahInfo();
			$ret['noi'] = $this->getNOISabahdata();	

		}
		else if ($this->project_owner == "SSLR2"){
			$ret['sd'] = $this->fetchSDInfoSSLR();
			$ret['ma'] = $this->fetchMAInfoSSLR();
			$ret['ms'] = $this->fetchMSInfoSSLR();
			$ret['ncr'] = $this->getNCRdataSSLR();
			$ret['rfi'] = $this->fetchRFIInfoSSLR($urw_flag);
			$ret['noi'] = $this->getNOIdataSSLR();
			$ret['wir'] = $this->getWIRdataSSLR();	
			$ret['section'] = $this->getSectionList();
		}
		else{
			$ret['sd'] = $this->fetchSDInfo();
			$ret['ma'] = $this->fetchMAInfo();
			$ret['ms'] = $this->fetchMSInfo();
			$ret['ncr'] = $this->getNCRdata();
			$ret['rfi'] = $this->fetchRFIInfo($urw_flag);
			$ret['noi'] = $this->getNOIdata();
			$ret['wir'] = $this->getWIRdata();	
			$ret['section'] = $this->getSectionList();
		}
		return $ret;
	}

	function getSectionList(){
		$ret = array();
		$sectionUrl = 'list_lookupSection?d-3687296-fn_package_id='.$this->projectID.'&d-3687296-fn_package_uuid=';

		if($this->isWPC){
			$res = $this->getCustomDatalistData($sectionUrl.$this->currPackageUuid, 'doc');
			
			if(isset($res['data']) && $res['data']){
				usort($res['data'], function($a, $b) {
					return strcmp($a["section"], $b["section"]);
				});
				foreach ($res['data'] as $sec) {
					$ret['overall'][] = $sec['section'];
				}
			}
		}
		foreach ($this->childProjectInfo as $childID) {
			$res = $this->getCustomDatalistData($sectionUrl.$childID['package_uuid'], 'doc');
			
			if (isset($res['data']) && $res['data']) {
				usort($res['data'], function($a, $b) {
				    return strcmp($a["section"], $b["section"]);
				});
				foreach ($res['data'] as $sec) {
					$ret[$childID['project_id']][] = $sec['section'];
				}
			}
		}

		return $ret;
	}

