	function fetchCorrInfo(){
		$ret = array();

		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_doc_register_corr', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			if (isset($res['data']) && $res['data']) {
				foreach ($res['data'] as $corr) {
					// based on month and year
					$dateCreated = strtotime($corr['c_doc_date']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					// total
					if (isset($ret['overall']['overall']['card']['all']['all']['total'])) {
						$ret['overall']['overall']['card']['all']['all']['total']++;
					}else{
						$ret['overall']['overall']['card']['all']['all']['total'] = 1;
					}
					if (isset($ret['overall']['overall']['card'][$year]['all']['total'])) {
						$ret['overall']['overall']['card'][$year]['all']['total']++;
					}else{
						$ret['overall']['overall']['card'][$year]['all']['total'] = 1;
					}
					if (isset($ret['overall']['overall']['card'][$year][$month]['total'])) {
						$ret['overall']['overall']['card'][$year][$month]['total']++;
					}else{
						$ret['overall']['overall']['card'][$year][$month]['total'] = 1;
					}

					if ($this->project_owner == "JKR_SABAH"){
						// only if third party is selected
						if(strtoupper($corr['c_third_party']) == 'YES'){

							//for conop linking filter
