								$ret['overall']['overall']['card']['all']['all']['allData'][$corr['c_doc_subtype']] = array('third_party' => $corr['c_third_party'], 'doc_subtype' => $corr['c_doc_subtype']);
							}
							if(!isset($ret['overall']['overall']['card'][$year]['all']['allData'][$corr['c_doc_subtype']])){
								$ret['overall']['overall']['card'][$year]['all']['allData'][$corr['c_doc_subtype']] = array('third_party' => $corr['c_third_party'], 'doc_subtype' => $corr['c_doc_subtype']);
							}
							if(!isset($ret['overall']['overall']['card'][$year][$month]['allData'][$corr['c_doc_subtype']])){
								$ret['overall']['overall']['card'][$year][$month]['allData'][$corr['c_doc_subtype']] = array('third_party' => $corr['c_third_party'], 'doc_subtype' => $corr['c_doc_subtype']);
							}

							// for counting the record for incoming or outgoing
