								$ret['overall']['overall']['card'][$year]['all'][$corr['c_doc_subtype']] = 1;
							}
							if (isset($ret['overall']['overall']['card'][$year][$month][$corr['c_doc_subtype']])) {
								$ret['overall']['overall']['card'][$year][$month][$corr['c_doc_subtype']]++;
							}else{
								$ret['overall']['overall']['card'][$year][$month][$corr['c_doc_subtype']] = 1;
							}

							$datetime1 = new DateTime($corr['dateCreated']);
