	function getDocumentInfo(){
		$ret = array();
		$ret['project_owner'] = $this->project_owner;
		if ($this->project_owner == "JKR_SARAWAK") {
			$ret['doc'] = $this->fetchRegisteredDocInfo();
			$ret['corr'] = $this->fetchCorrInfo();
			$ret['section'] = $this->getSectionList();
		}else if ($this->project_owner == "SSLR2") {
			$ret['doc'] = $this->fetchRegisteredDocInfoSSLR();
			$ret['corr'] = $this->fetchCorrInfo();
			$ret['section'] = $this->getSectionList();
		}else{
			$ret['doc'] = $this->fetchRegisteredDocInfo();
			$ret['corr'] = $this->fetchCorrInfo();
		}

		return $ret;
	}

	// taken from joget.php [return instead of echo + variable]
	function getJogetProcessRecords($processName, $projectID)
	{
		// parent project does not have $_SESSION['appsLinks'] 
	    $url = $this->jogetHostIP ."jw/web/json/data/list/".$this->jogetConstructApp;
	    switch($processName){
	        case "NCR":
	            $host = $url."/list_ncrForm?rows=90000&d-6458202-fn_Package=".$projectID; 
	        break;
	        case "WIR":
	            $host = $url."/list_wirForm?rows=90000&d-6466221-fn_Package=".$projectID;
	        break;
	        case "RFI":
	            $host = $url."/list_rfiForm?rows=90000&d-7745341-fn_Package=".$projectID;
	        break;
	        case "MOS":
	            $host = $url."/list_msForm?rows=90000&d-1313633-fn_Package=".$projectID;
	        break;
	        case "MS":
	            $host = $url."/list_maForm?rows=90000&d-7743883-fn_Package=".$projectID;
	        break;
	        case "IR":
	            $host = $url."/list_incForm?rows=90000&d-6456015-fn_c_Package=".$projectID;
	        break;
	        case "RS":
	            $host = $url."/list_rsForm?rows=90000&d-7746556-fn_Package=".$projectID;
	        break;
	    }

	    $headers = array(
	        'Content-Type: application/json',
	        'Authorization: Basic ' . base64_encode("$this->api_username:$this->api_password")
	    );
	    $ch = curl_init($host);
	    curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
	    curl_setopt($ch, CURLOPT_TIMEOUT, 30);
	    curl_setopt($ch, CURLOPT_POST, 1);
	    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
	    $return = curl_exec($ch);
	    $err    = curl_error($ch);
	    curl_close($ch);
	    if ($err) {
	        return false;
	    } else {
	        return json_decode($return, true);
	    }
	}

	function getCustomDatalistData($dataListUrl, $app = "construct", $row = 0){
		switch ($app) {
			case 'doc':
				$jogetApp = $this->jogetDocApp;
				break;
			case 'pfs':
				$jogetApp = $this->jogetPFSApp;
				break;
			case 'construct':
			default:
				$jogetApp = $this->jogetConstructApp;
				break;
		}
	    $url = $this->jogetHostIP ."jw/web/json/data/list/".$jogetApp.'/'.$dataListUrl.'&rows='.(($row != 0) ? $row : '90000');
	    $headers = array(
	        'Content-Type: application/json',
	        'Authorization: Basic ' . base64_encode("$this->api_username:$this->api_password")
	    );
	    $ch = curl_init($url);
	    curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
	    curl_setopt($ch, CURLOPT_TIMEOUT, 30);
	    curl_setopt($ch, CURLOPT_POST, 1);
	    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
	    $return = curl_exec($ch);
	    $err    = curl_error($ch);
	    curl_close($ch);
	    if ($err) {
	        return false;
	    } else {
	        return json_decode($return, true);
	    }	
	}

	function fetchPublicComplaintInfo(){
		$ret = array();
		$pcCategoryArray = array();
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_cons_PBS', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			if (isset($res['data']) && $res['data']) {
				foreach ($res['data'] as $pc) {
					// based on month and year
					$dateCreated = strtotime($pc['date_received']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					if($this->project_owner == "JKR_SABAH"){
						if (isset($ret['overall']['card']['all']['all']['total'])) {
							$ret['overall']['card']['all']['all']['total']++;
						}else{
							$ret['overall']['card']['all']['all']['total'] = 1;
						}
						if (isset($ret['overall']['card'][$year]['all']['total'])) {
							$ret['overall']['card'][$year]['all']['total']++;
						}else{
							$ret['overall']['card'][$year]['all']['total'] = 1;
						}
						if (isset($ret['overall']['card'][$year][$month]['total'])) {
							$ret['overall']['card'][$year][$month]['total']++;
						}else{
							$ret['overall']['card'][$year][$month]['total'] = 1;
						}

						$pc['status'] = strtolower($pc['status']);
						if (isset($ret['overall']['card']['all']['all'][$pc['status']]['total'])) {
							$ret['overall']['card']['all']['all'][$pc['status']]['total']++;
						}else{
							$ret['overall']['card']['all']['all'][$pc['status']]['total'] = 1;
						}
						if (isset($ret['overall']['card'][$year]['all'][$pc['status']]['total'])) {
							$ret['overall']['card'][$year]['all'][$pc['status']]['total']++;
						}else{
							$ret['overall']['card'][$year]['all'][$pc['status']]['total'] = 1;
						}
						if (isset($ret['overall']['card'][$year][$month][$pc['status']]['total'])) {
							$ret['overall']['card'][$year][$month][$pc['status']]['total']++;
						}else{
							$ret['overall']['card'][$year][$month][$pc['status']]['total'] = 1;
						}

						$pcCategoryArray = explode(';', $pc['category']);
						foreach ($pcCategoryArray as $pc2){
							if (isset($ret['overall']['cat']['all']['all']['allStatus'][$pc2])) {
								$ret['overall']['cat']['all']['all']['allStatus'][$pc2]++;
							}else{
								$ret['overall']['cat']['all']['all']['allStatus'][$pc2] = 1;
							}
							if (isset($ret['overall']['cat'][$year]['all']['allStatus'][$pc2])) {
								$ret['overall']['cat'][$year]['all']['allStatus'][$pc2]++;
							}else{
								$ret['overall']['cat'][$year]['all']['allStatus'][$pc2] = 1;
							}
							if (isset($ret['overall']['cat'][$year][$month]['allStatus'][$pc2])) {
								$ret['overall']['cat'][$year][$month]['allStatus'][$pc2]++;
							}else{
								$ret['overall']['cat'][$year][$month]['allStatus'][$pc2] = 1;
							}
	
							if (isset($ret['overall']['cat']['all']['all'][$pc['status']][$pc2])) {
								$ret['overall']['cat']['all']['all'][$pc['status']][$pc2]++;
							}else{
								$ret['overall']['cat']['all']['all'][$pc['status']][$pc2] = 1;
