					// total
					if (isset($ret[$rs['package_id']]['all']['all']['card']['allcategory']['total'])) {
						$ret[$rs['package_id']]['all']['all']['card']['allcategory']['total']++;
					}else{
						$ret[$rs['package_id']]['all']['all']['card']['allcategory']['total'] = 1;
					}
					if (isset($ret[$rs['package_id']][$year]['all']['card']['allcategory']['total'])) {
						$ret[$rs['package_id']][$year]['all']['card']['allcategory']['total']++;
					}else{
						$ret[$rs['package_id']][$year]['all']['card']['allcategory']['total'] = 1;
					}
					if (isset($ret[$rs['package_id']][$year][$month]['card']['allcategory']['total'])) {
						$ret[$rs['package_id']][$year][$month]['card']['allcategory']['total']++;
					}else{
						$ret[$rs['package_id']][$year][$month]['card']['allcategory']['total'] = 1;
					}

					$rsStatus = strtolower($rs['status']) == "closed" ? "closed" : "pending";
					// total
					if (isset($ret[$rs['package_id']]['all']['all']['card']['allcategory'][$rsStatus])) {
						$ret[$rs['package_id']]['all']['all']['card']['allcategory'][$rsStatus]++;
					}else{
						$ret[$rs['package_id']]['all']['all']['card']['allcategory'][$rsStatus] = 1;
					}
					if (isset($ret[$rs['package_id']][$year]['all']['card']['allcategory'][$rsStatus])) {
						$ret[$rs['package_id']][$year]['all']['card']['allcategory'][$rsStatus]++;
					}else{
						$ret[$rs['package_id']][$year]['all']['card']['allcategory'][$rsStatus] = 1;
					}
					if (isset($ret[$rs['package_id']][$year][$month]['card']['allcategory'][$rsStatus])) {
						$ret[$rs['package_id']][$year][$month]['card']['allcategory'][$rsStatus]++;
					}else{
						$ret[$rs['package_id']][$year][$month]['card']['allcategory'][$rsStatus] = 1;
					}

					// total based on category
					if (isset($ret[$rs['package_id']]['all']['all']['card'][$rs['category']]['total'])) {
						$ret[$rs['package_id']]['all']['all']['card'][$rs['category']]['total']++;
					}else{
						$ret[$rs['package_id']]['all']['all']['card'][$rs['category']]['total'] = 1;
					}
					if (isset($ret[$rs['package_id']][$year]['all']['card'][$rs['category']]['total'])) {
						$ret[$rs['package_id']][$year]['all']['card'][$rs['category']]['total']++;
					}else{
						$ret[$rs['package_id']][$year]['all']['card'][$rs['category']]['total'] = 1;
					}
					if (isset($ret[$rs['package_id']][$year][$month]['card'][$rs['category']]['total'])) {
						$ret[$rs['package_id']][$year][$month]['card'][$rs['category']]['total']++;
					}else{
						$ret[$rs['package_id']][$year][$month]['card'][$rs['category']]['total'] = 1;
					}

					// pending or closed based on category
					if (isset($ret[$rs['package_id']]['all']['all']['card'][$rs['category']][$rsStatus])) {
						$ret[$rs['package_id']]['all']['all']['card'][$rs['category']][$rsStatus]++;
					}else{
						$ret[$rs['package_id']]['all']['all']['card'][$rs['category']][$rsStatus] = 1;
					}
					if (isset($ret[$rs['package_id']][$year]['all']['card'][$rs['category']][$rsStatus])) {
						$ret[$rs['package_id']][$year]['all']['card'][$rs['category']][$rsStatus]++;
					}else{
						$ret[$rs['package_id']][$year]['all']['card'][$rs['category']][$rsStatus] = 1;
					}
					if (isset($ret[$rs['package_id']][$year][$month]['card'][$rs['category']][$rsStatus])) {
						$ret[$rs['package_id']][$year][$month]['card'][$rs['category']][$rsStatus]++;
					}else{
						$ret[$rs['package_id']][$year][$month]['card'][$rs['category']][$rsStatus] = 1;
					}

					// chart for category
					if (isset($ret[$rs['package_id']]['all']['all']['chart']['allstatus'][$rs['category']])) {
						$ret[$rs['package_id']]['all']['all']['chart']['allstatus'][$rs['category']]++;
					}else{
						$ret[$rs['package_id']]['all']['all']['chart']['allstatus'][$rs['category']] = 1;
					}
					if (isset($ret[$rs['package_id']][$year]['all']['chart']['allstatus'][$rs['category']])) {
						$ret[$rs['package_id']][$year]['all']['chart']['allstatus'][$rs['category']]++;
					}else{
						$ret[$rs['package_id']][$year]['all']['chart']['allstatus'][$rs['category']] = 1; 
					}
					if (isset($ret[$rs['package_id']][$year][$month]['chart']['allstatus'][$rs['category']])) {
						$ret[$rs['package_id']][$year][$month]['chart']['allstatus'][$rs['category']]++;
					}else{
						$ret[$rs['package_id']][$year][$month]['chart']['allstatus'][$rs['category']] = 1;
					}

					// chart for category based on status
					if (isset($ret[$rs['package_id']]['all']['all']['chart'][$rsStatus][$rs['category']])) {
						$ret[$rs['package_id']]['all']['all']['chart'][$rsStatus][$rs['category']]++;
					}else{
						$ret[$rs['package_id']]['all']['all']['chart'][$rsStatus][$rs['category']] = 1;
					}
					if (isset($ret[$rs['package_id']][$year]['all']['chart'][$rsStatus][$rs['category']])) {
						$ret[$rs['package_id']][$year]['all']['chart'][$rsStatus][$rs['category']]++;
					}else{
						$ret[$rs['package_id']][$year]['all']['chart'][$rsStatus][$rs['category']] = 1; 
					}
					if (isset($ret[$rs['package_id']][$year][$month]['chart'][$rsStatus][$rs['category']])) {
						$ret[$rs['package_id']][$year][$month]['chart'][$rsStatus][$rs['category']]++;
					}else{
						$ret[$rs['package_id']][$year][$month]['chart'][$rsStatus][$rs['category']] = 1;
					}
					//-----------END CHILD---------------//
				}
			}
		}
		return $ret;
	}

	function id_compare($a, $b)
	{
	    $t1 = $a['contract_id'];
	    $t2 = $b['contract_id'];
	    return $t1 - $t2;
	} 

	function id_compareSabah($b, $a)
	{
	    $t1 = $a['contract_id'];
	    $t2 = $b['contract_id'];
	    return $t1 - $t2;
	} 

	function fetchContractPart(){
		$ret = array();

		if($this->isWPC){
			$url = $this->jogetLinkObj->getLink('finance_dash_contract').$this->projectID;
			$resContract = $this->jogetCURL($url);
			if (isset($resContract['data'])) {
				$tempArr = $resContract['data'];
				
				$dataArr = array();
				foreach ($tempArr as $val) {
					if ($val['archive'] != 'true') {
						$dataArr[] = $val;
					}
				}

				// sort by id and take only latest one
				usort($dataArr, array($this, 'id_compare'));
				$dataSection = array();
				$contractNameArr = array();

				if($dataArr){
					foreach ($dataArr as $co) {
						// change the date format completion_date, loa_date, revised_completion_date
						if($co['revised_completion_date']){
							$co['revised_completion_date'] = date('d-m-Y', strtotime($co['revised_completion_date']));
						}
	
						if($co['loa_date']){
							$co['loa_date'] = date('d-m-Y', strtotime($co['loa_date']));
						}
	
						if($co['site_possession_date']){
							$co['site_possession_date'] = date('d-m-Y', strtotime($co['site_possession_date']));
						}
	
						if($co['completion_date']){
							$co['completion_date'] = DateTime::createFromFormat('d/m/Y', $co['completion_date'])->format('d-m-Y');
						}
	
						$ret['overall'][$co['section']] = $co;
					}
	
					$dataSection = $ret['overall'];

					foreach ($dataSection as $key => $data) {
						//contract sum card
						if(isset($ret['overall']['overall']['original_amount'])){
							$ret['overall']['overall']['original_amount'] = $ret['overall']['overall']['original_amount'] + (float) $data['original_amount'];
						}
						else{
							$ret['overall']['overall']['original_amount'] = (float) $data['original_amount'];
						}
	
						//revised contract sum card
						if(isset($ret['overall']['overall']['new_amount_after_revised'])){
							$ret['overall']['overall']['new_amount_after_revised'] = $ret['overall']['overall']['new_amount_after_revised'] + (float) $data['new_amount'];
						}
						else{
							$ret['overall']['overall']['new_amount_after_revised'] = (float) $data['new_amount'];
						}
	
						//total ipa amount card
						if(isset($ret['overall']['overall']['total_claim_vo_and_claim'])){
							$ret['overall']['overall']['total_claim_vo_and_claim'] = $ret['overall']['overall']['total_claim_vo_and_claim'] + (float) $data['total_claim_vo_and_claim'];
						}
						else{
							$ret['overall']['overall']['total_claim_vo_and_claim'] = (float) $data['total_claim_vo_and_claim'];
						}
	
						//total recommended amount card
						if(isset($ret['overall']['overall']['cumulative_certified_amount'])){
							$ret['overall']['overall']['cumulative_certified_amount'] = $ret['overall']['overall']['cumulative_certified_amount'] + (float) $data['cumulative_certified_amount'];
						}
						else{
							$ret['overall']['overall']['cumulative_certified_amount'] = (float) $data['cumulative_certified_amount'];
						}
						
						//total received amount card
						if(isset($ret['overall']['overall']['cumulative_payment_received'])){
							$ret['overall']['overall']['cumulative_payment_received'] = $ret['overall']['overall']['cumulative_payment_received'] + (float) $data['cumulative_payment_received'];
						}
						else{
							$ret['overall']['overall']['cumulative_payment_received'] = (float) $data['cumulative_payment_received'];
						}
	
						if($data['contract_type']){
							if($data['contract_type'] == "Retainage"){
								if ($data['retainage_held_on'] == "Original Contract Amount"){
									$amountRetainage = (float) $data['orignal_amount_retainage'];
									$amountVO = (float) $data['variation_amount'];
									$claimAmoutRetain = $amountRetainage + $amountVO; //have to add VO amount also
									if(isset($usedClaimAmountRetain)){
										$usedClaimAmountRetain = $usedClaimAmountRetain + (float) $claimAmoutRetain;
									}
									else{
										$usedClaimAmountRetain = (float) $claimAmoutRetain;
									}
	
								}
								else{
									$claimAmoutRetain = (float) $data['field62'];
									if(isset($usedClaimAmountRetain)){
										$usedClaimAmountRetain = $usedClaimAmountRetain + (float) $claimAmoutRetain;
									}
									else{
										$usedClaimAmountRetain = (float) $claimAmoutRetain;
									}
								}
							}
							else{
								$claimAmoutRetain = (float) $data['new_amount'];
								if(isset($usedClaimAmountRetain)){
									$usedClaimAmountRetain = $usedClaimAmountRetain + (float) $claimAmoutRetain;
								}
								else{
									$usedClaimAmountRetain = (float) $claimAmoutRetain;
								}
							}
						}
						else{
							$claimAmoutRetain = (float) $data['new_amount_after_revised'];
							if(isset($usedClaimAmountRetain)){
								$usedClaimAmountRetain = $usedClaimAmountRetain + (float) $claimAmoutRetain;
							}
							else{
								$usedClaimAmountRetain = (float) $claimAmoutRetain;
							}
						}
	
						$totalCertifiedAmount = (float) $ret['overall']['overall']['cumulative_certified_amount'];

						$remainingClaimAmount = $usedClaimAmountRetain - $totalCertifiedAmount;
					}
	
					if(isset($ret['overall']['overall']['remaining_claim_amount'])){
						$ret['overall']['overall']['remaining_claim_amount'] = $ret['overall']['overall']['remaining_claim_amount'] + (float) $remainingClaimAmount;
					}
					else{
						$ret['overall']['overall']['remaining_claim_amount'] = (float) $remainingClaimAmount;
					}
				}
				
			}
		}

		foreach ($this->childProjectInfo as $childID){
			$url = $this->jogetLinkObj->getLink('finance_dash_contract').$childID['project_id'];
			$resContract = $this->jogetCURL($url);
