						}
	
						//revised contract sum card
						if(isset($ret[$childID['project_id']]['overall']['new_amount_after_revised'])){
							$ret[$childID['project_id']]['overall']['new_amount_after_revised'] = $ret[$childID['project_id']]['overall']['new_amount_after_revised'] + (float) $data['new_amount'];
						}
