	function fetchSSLRContractPart(){
		$ret = array();

		if($this->isWPC){
			$url = $this->jogetLinkObj->getLink('finance_dash_contract_SSLR2').$this->projectID;
			$resContract = $this->jogetCURL($url);
			if (isset($resContract['data'])) {
				$tempArr = $resContract['data'];
				
				$dataArr = array();
				foreach ($tempArr as $val) {
					if ($val['archive'] != 'true') {
						$dataArr[] = $val;
					}
				}

				// sort by id and take only latest one
				usort($dataArr, array($this, 'id_compare'));

				$dataSection = array();
				$contractNameArr = array();

				if($dataArr){
					foreach ($dataArr as $co) {
						// change the date format completion_date, loa_date, revised_completion_date
						if($co['revised_completion_date']){
							$co['revised_completion_date'] = date('d-m-Y', strtotime($co['revised_completion_date']));
						}
	
						if($co['loa_date']){
							$co['loa_date'] = date('d-m-Y', strtotime($co['loa_date']));
						}
	
						if($co['site_possession_date']){
							$co['site_possession_date'] = date('d-m-Y', strtotime($co['site_possession_date']));
						}
	
						if($co['completion_date']){
							$co['completion_date'] = DateTime::createFromFormat('d/m/Y', $co['completion_date'])->format('d-m-Y');
						}
	
						$ret['overall'] = $co;
					}
	
					$data = $ret['overall'];

					//contract sum card
					if(isset($ret['overall']['original_amount'])){
						if(!is_numeric($data['original_amount'])){
							$data['original_amount'] = str_replace(',', '', $data['original_amount']);
						}
