	function getSSLRLeadConsultant($project_id)
	{
		$lead_consultants = [];

		$urlL = $this->jogetLinkObj->getLink('finance_contract_lead_consultant').$project_id;
		$reslc = $this->jogetCURL($urlL);
		if (isset($reslc['data'])) {
			foreach ($reslc['data'] as $lc) {
				$lead_consultants[$lc['id']] = $lc['lead_consultant'];
			}
		}
		return $lead_consultants;
	}

