	function fetchClaimDetail(){
		$ret = array();
		if (!$this->contractInfo) return;

		if($this->isWPC){
			if (!isset($this->contractInfo['overall'])) return;

			foreach ($this->contractInfo['overall'] as $section => $contractArr) {
				if(!isset($contractArr['contract_id'])) continue;

				$contractId = $contractArr['contract_id'];

				$url = $this->jogetLinkObj->getLink('finance_dash_claim', array($contractId, $this->projectID));
				$res = $this->jogetCURL($url);
				if(isset($res['data'])){
					foreach ($res['data'] as $co) {
						// based on month and year
						$dateCreated = strtotime($co['interim_date_submission']);
						$year = date("Y", $dateCreated);
						$month = date("M", $dateCreated);

						$ret['overall']['overall']['all']['raw'][] = $co;
						$ret['overall']['overall'][$year]['raw'][] = $co;

						if(isset($ret['overall']['overall']['all']['calculateCard']['totalInterimAmount'])){
							$ret['overall']['overall']['all']['calculateCard']['totalInterimAmount'] = $ret['overall']['overall']['all']['calculateCard']['totalInterimAmount'] + (double) str_replace(",", "", $co['total_claim_value']);
						}
						else{
							$ret['overall']['overall']['all']['calculateCard']['totalInterimAmount'] = (double) str_replace(",", "", $co['total_claim_value']);
						}
						if(isset($ret['overall']['overall'][$year]['calculateCard']['totalInterimAmount'])){
							$ret['overall']['overall'][$year]['calculateCard']['totalInterimAmount'] = $ret['overall']['overall'][$year]['calculateCard']['totalInterimAmount'] + (double) str_replace(",", "", $co['total_claim_value']);
						}
						else{
							$ret['overall']['overall'][$year]['calculateCard']['totalInterimAmount'] = (double) str_replace(",", "", $co['total_claim_value']);
						}


						if(isset($ret['overall']['overall']['all']['calculateCard']['totalIpcRecAmount'])){
							$ret['overall']['overall']['all']['calculateCard']['totalIpcRecAmount'] = $ret['overall']['overall']['all']['calculateCard']['totalIpcRecAmount'] + (double) str_replace(",", "", $co['certified_claim_amount']);
						}
						else{
							$ret['overall']['overall']['all']['calculateCard']['totalIpcRecAmount'] = (double) str_replace(",", "", $co['certified_claim_amount']);
						}
						if(isset($ret['overall']['overall'][$year]['calculateCard']['totalIpcRecAmount'])){
							$ret['overall']['overall'][$year]['calculateCard']['totalIpcRecAmount'] = $ret['overall']['overall'][$year]['calculateCard']['totalIpcRecAmount'] + (double) str_replace(",", "", $co['certified_claim_amount']);
						}
						else{
							$ret['overall']['overall'][$year]['calculateCard']['totalIpcRecAmount'] = (double) str_replace(",", "", $co['certified_claim_amount']);
