					}

					if(!isset($ret['overall']['all']['calculateCard']['eotDays'])){
						$ret['overall']['all']['calculateCard']['eotDays'] = $data['approved_eot_days'];
					}

					if(!isset($ret['overall']['all']['calculateCard']['id'])){
						$ret['overall']['all']['calculateCard']['id'] = $data['id'];
					}
				}
			}
		}

		foreach ($this->childProjectInfo as $childID){
			if (!isset($this->contractInfo[$childID['project_id']])) continue;

			$contractId = $this->contractInfo[$childID['project_id']]['contract_id'];

			$url = $this->jogetLinkObj->getLink('finance_dash_eot_SSLR2', array($contractId, $childID['project_id']));
			$res = $this->jogetCURL($url);
			if(isset($res['data'])){
				usort($res['data'], function($a, $b) {
					return strtotime($a['approved_eot_date']) - strtotime($b['approved_eot_date']);
				});

				if(isset($res['data']) && isset($res['data'][0])){
					$co = $res['data'][0];

					$ret[$childID['project_id']]['all']['raw'][] = $co;

					if(!isset($ret[$childID['project_id']]['all']['calculateCard']['eotNo'])){
						$ret[$childID['project_id']]['all']['calculateCard']['eotNo'] = $co['eot_no'];
					}

					if(!isset($ret[$childID['project_id']]['all']['calculateCard']['eotDays'])){
						$ret[$childID['project_id']]['all']['calculateCard']['eotDays'] = $co['approved_eot_days'];
					}

					if(!isset($ret[$childID['project_id']]['all']['calculateCard']['id'])){
						$ret[$childID['project_id']]['all']['calculateCard']['id'] = $co['id'];
					}
				}
			}
		}

		return $ret;
	}

