	function getSectionAssetData(){
		$ret = array();
		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_asset_section', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			if (isset($res['data']) && $res['data']) {
				foreach ($res['data'] as $sc) {
					// length without section
					if (isset($ret['overall']['card']['length']['allSectionLength'])) {
						$ret['overall']['card']['length']['allSectionLength'] = $ret['overall']['card']['length']['allSectionLength'] + (float) $sc['c_geo_length_km'];
					}else{
						$ret['overall']['card']['length']['allSectionLength'] = (float) $sc['c_geo_length_km'];
					}

					// length by section
					if (isset($ret['overall']['card']['length'][$sc['c_site_name']])) {
						$ret['overall']['card']['length'][$sc['c_site_name']] = $ret['overall']['card']['length'][$sc['c_site_name']] + (float) $sc['c_geo_length_km'];
					}else{
						$ret['overall']['card']['length'][$sc['c_site_name']] = (float) $sc['c_geo_length_km'];
					}

					// get division name
					if (!isset($ret['overall']['chart']['division'][$sc['c_package_id']])) {
						$ret['overall']['chart']['division'][$sc['c_package_id']] = $sc['c_site_name'];
					}
				}
			}
		}
		else{
			$url = $this->jogetLinkObj->getLink('dash_asset_section', array('', $this->projectID));
			$res = $this->jogetCURL($url);
			if (isset($res['data']) && $res['data']) {
				foreach ($res['data'] as $sc) {
					// length without section
					if (isset($ret['overall']['card']['length']['allSectionLength'])) {
						$ret['overall']['card']['length']['allSectionLength'] = $ret['overall']['card']['length']['allSectionLength'] + (float) $sc['c_geo_length_km'];
					}else{
						$ret['overall']['card']['length']['allSectionLength'] = (float) $sc['c_geo_length_km'];
					}

					// length by section
					if (isset($ret['overall']['card']['length'][$sc['c_site_name']])) {
						$ret['overall']['card']['length'][$sc['c_site_name']] = $ret['overall']['card']['length'][$sc['c_site_name']] + (float) $sc['c_geo_length_km'];
					}else{
						$ret['overall']['card']['length'][$sc['c_site_name']] = (float) $sc['c_geo_length_km'];
					}

					//--------START CHILD-------//
					// length without section
					if (isset($ret[$sc['c_package_id']]['card']['length']['allSectionLength'])) {
						$ret[$sc['c_package_id']]['card']['length']['allSectionLength'] = $ret[$sc['c_package_id']]['card']['length']['allSectionLength'] + (float) $sc['c_geo_length_km'];
					}else{
						$ret[$sc['c_package_id']]['card']['length']['allSectionLength'] = (float) $sc['c_geo_length_km'];
					}

					// length by section
					if (isset($ret[$sc['c_package_id']]['card']['length'][$sc['c_site_name']])) {
						$ret[$sc['c_package_id']]['card']['length'][$sc['c_site_name']] = $ret[$sc['c_package_id']]['card']['length'][$sc['c_site_name']] + (float) $sc['c_geo_length_km'];
					}else{
						$ret[$sc['c_package_id']]['card']['length'][$sc['c_site_name']] = (float) $sc['c_geo_length_km'];
					}
					//---------END CHILD---------//

					// get division name
					if (!isset($ret['overall']['chart']['division'][$sc['c_package_id']])) {
						$ret['overall']['chart']['division'][$sc['c_package_id']] = $sc['c_site_name'];
					}					

					if (!isset($ret[$sc['c_package_id']]['chart']['division'][$sc['c_package_id']])) {
						$ret[$sc['c_package_id']]['chart']['division'][$sc['c_package_id']] = $sc['c_site_name'];
					}
				}
			}
		}

		return $ret;
	}

	public function getProcurementInfo(){
		$ret = array();
		$claimInfo = [];

		if ($this->project_owner == "JKR_SARAWAK"){
			$ret['section'] = $this->getSectionList();
			$this->contractInfo = $this->fetchContractPart();
			if ($this->contractInfo) {
				$ret['claim_detail'] = $this->fetchClaimDetail();
			}

		}
		else if($this->project_owner == 'SSLR2') {
			if($this->isDownStream){
				$this->contractInfo = $this->fetchSSLRDownStreamContractPart();
				if ($this->contractInfo) {
					$ret['claim_detail'] = $this->fetchSSLRDownstreamClaimDetail();
					$ret['vo_detail'] = $this->fetchSSLRDownStreamVODetail();
					$ret['acs_detail'] = $this->fetchSSLRDownStreamAcsDetail();
					$ret['eot_detail'] = $this->fetchSSLRDownStreamEotDetail();

				}
			}else{
				$this->contractInfo = $this->fetchSSLRContractPart();
				if ($this->contractInfo) {
					$ret['claim_detail'] = $this->fetchSSLRClaimDetail();
					$ret['vo_detail'] = $this->fetchSSLRVODetail();
				}
			}
		}
		else{
			$this->contractInfo = $this->fetchContractPartSabah();
			if ($this->contractInfo) {
				$ret['claim_detail'] = $this->fetchClaimDetailSabah();
			}

		}

		$ret['contract_particular'] = $this->contractInfo;	

		return $ret;
	}

