	function fetchPCAStripmapData($date){
		$maxChgVal = '0';
		$fwdDate = ($date != '') ? $date : $this->db->fetchOne('select max(fwd_data_date) from asset_analysis_fwd where fwd_package_id=:0', array($this->projectID));
		// FWD - group the data by the chainage
		$fwdData = $this->db->fetchAll("select * from asset_analysis_fwd where fwd_data_date= :0 and fwd_package_id=:1", array($fwdDate, $this->projectID));
		$fwdChgData = array();
		foreach ($fwdData as $chgVal) {
			$maxChgVal = ($maxChgVal > (float) $chgVal['fwd_chainage']) ? $maxChgVal : (float) $chgVal['fwd_chainage'];
			$fwdChgData[$chgVal['fwd_direction']][$chgVal['fwd_lane']][(string) $chgVal['fwd_chainage']] = $chgVal; 
		}

		$rmtDate =  ($date != '') ? $date : $this->db->fetchOne('select max(rmt_data_date) from asset_analysis_rmt where rmt_package_id=:0', array($this->projectID));
		//RMT - group the data by the chainage 
		$rmtDataInc = $this->db->fetchAll("select * from asset_analysis_rmt where rmt_data_date= :0 and rmt_package_id=:1", array($rmtDate, $this->projectID));
		$rmtChgData = array();
		foreach ($rmtDataInc as $chgVal) {
			$maxChgVal = ($maxChgVal > (float) $chgVal['rmt_chainage']) ? $maxChgVal : (float) $chgVal['rmt_chainage'];
			$chgVal['e3_calc'] = number_format($chgVal['rmt_sub_base_layer_e3']/$chgVal['rmt_subgrade_es'], 3);
			$chgVal['e2_calc'] = number_format($chgVal['rmt_base_layer_e2']/$chgVal['rmt_subgrade_es'], 3);
			$rmtChgData[$chgVal['rmt_direction']][$chgVal['rmt_lane']][(string) $chgVal['rmt_chainage']] = $chgVal; 
		}

		// mpl
		$mlpDate =  ($date != '') ? $date : $this->db->fetchOne('select max(mlp_data_date) from asset_analysis_mlp where mlp_package_id=:0', array($this->projectID));
		//RMT - group the data by the chainage 
		$mlpDataInc = $this->db->fetchAll("select * from asset_analysis_mlp where mlp_data_date= :0 and mlp_package_id =:1", array($mlpDate, $this->projectID));
		$mlpChgData = array();
		foreach ($mlpDataInc as $chgVal) {
			$maxChgVal = ($maxChgVal > (float) $chgVal['mlp_start_chg']) ? $maxChgVal : (float) $chgVal['mlp_start_chg'];
			$mlpChgData[$chgVal['mlp_direction']]['Fast'][(float) $chgVal['mlp_start_chg']] = array(
				'all_crack' => $chgVal['mlp_fast_all_cracks'],
				'iri' => $chgVal['mlp_fast_roughness'],
				'rutting' => $chgVal['mlp_fast_rutting']
			); 

			$mlpChgData[$chgVal['mlp_direction']]['Slow'][(float) $chgVal['mlp_start_chg']] = array(
				'all_crack' => $chgVal['mlp_slow_all_cracks'],
				'iri' => $chgVal['mlp_slow_roughness'],
				'rutting' => $chgVal['mlp_slow_rutting']
			); 
		}
		return array(
			'fwd' =>  $fwdChgData,
			'rmt' => $rmtChgData,
			'mlp' => $mlpChgData,
			'maxChg' => $maxChgVal,
			'currDate' => array(
				'fwd' => date('d-m-Y',strtotime($fwdDate)),
				'rmt' => date('d-m-Y',strtotime($rmtDate)),
				'mlp' => date('d-m-Y',strtotime($mlpDate)),
			),
		);
	}

	function getPCAStripmap($date = ''){
		$ret = $this->fetchPCAStripmapData($date);
		$ret['dateOptions'] = $this->getAssetAnalysisDateOpts();
		$ret['chgOptions'] = $this->getAssetAnalysisChgOpts();
		return $ret;
	}

	function getCDData($date, $lane, $minChg, $maxChg){
		$ret = array();
		$fwdGood = $this->db->fetchAll("select count(fwd_d1) as cnt, fwd_direction from asset_analysis_fwd where fwd_data_date = :0 and fwd_lane = :1 and CONVERT (float, fwd_d1) < 400 and fwd_chainage >=:2 and fwd_chainage <= :3 and fwd_package_id=:4 group by fwd_direction", array($date, $lane, $minChg, $maxChg, $this->projectID));
		foreach ($fwdGood as $val) {
			$ret[$val['fwd_direction']]['Good'] = $val['cnt'];
		}
		$fwdFair = $this->db->fetchAll("select count(fwd_d1) as cnt, fwd_direction from asset_analysis_fwd where fwd_data_date = :0 and fwd_lane = :1 and CONVERT (float, fwd_d1) >= 400 and CONVERT (float, fwd_d1) <= 700 and fwd_chainage >=:2 and fwd_chainage <= :3 and fwd_package_id=:4 group by fwd_direction", array($date, $lane, $minChg, $maxChg, $this->projectID));
		foreach ($fwdFair as $val) {
			$ret[$val['fwd_direction']]['Fair'] = $val['cnt'];
		}
		$fwdPoor = $this->db->fetchAll("select count(fwd_d1) as cnt, fwd_direction from asset_analysis_fwd where fwd_data_date = :0 and fwd_lane = :1 and CONVERT (float, fwd_d1) > 700 and fwd_chainage >=:2 and fwd_chainage <= :3  and fwd_package_id=:4 group by fwd_direction", array($date, $lane, $minChg, $maxChg, $this->projectID));
		foreach ($fwdPoor as $val) {
			$ret[$val['fwd_direction']]['Poor'] = $val['cnt'];
		}
		return $ret;
	}

	function getRMData($date, $lane, $minChg, $maxChg){
		$ret = array();
		$rmCondData = $this->db->fetchAll("select
		rmt_direction,
		case when CONVERT (float, rmt_asphalt_e1) < 2500 then 'Poor' when CONVERT (float, rmt_asphalt_e1) <= 3500 then 'Statisfactory' else 'Good' end as e1_condition,
		case when CONVERT (float, rmt_base_layer_e2)/CONVERT (float, rmt_subgrade_es) < 1.5 then 'Poor' when CONVERT (float, rmt_base_layer_e2)/CONVERT (float, rmt_subgrade_es) <= 2.0 then 'Statisfactory' else 'Good' end as e2_condition,
		case when CONVERT (float, rmt_sub_base_layer_e3)/CONVERT (float, rmt_subgrade_es) < 1 then 'Poor' when CONVERT (float, rmt_sub_base_layer_e3)/CONVERT (float, rmt_subgrade_es) <= 1.5 then 'Statisfactory' else 'Good' end as e3_condition,
		case when CONVERT (float, rmt_subgrade_es) < 50 then 'Poor' when CONVERT (float, rmt_subgrade_es) <= 100 then 'Statisfactory' else 'Good' end as es_condition
		from asset_analysis_rmt where rmt_data_date = :0 and rmt_lane = :1 and CONVERT (float, rmt_chainage) >= :2 and CONVERT (float, rmt_chainage) <= :3 and rmt_package_id=:4", array($date, $lane, $minChg, $maxChg, $this->projectID));
		
		foreach ($rmCondData as $val) {
			if(isset($ret[$val['rmt_direction']]['e1'][$val['e1_condition']])){
				$ret[$val['rmt_direction']]['e1'][$val['e1_condition']]++;
			}else{
				$ret[$val['rmt_direction']]['e1'][$val['e1_condition']] = 1;
			}
			if(isset($ret[$val['rmt_direction']]['e2'][$val['e2_condition']])){
				$ret[$val['rmt_direction']]['e2'][$val['e2_condition']]++;
			}else{
				$ret[$val['rmt_direction']]['e2'][$val['e2_condition']] = 1;
			}
			if(isset($ret[$val['rmt_direction']]['e3'][$val['e3_condition']])){
				$ret[$val['rmt_direction']]['e3'][$val['e3_condition']]++;
			}else{
				$ret[$val['rmt_direction']]['e3'][$val['e3_condition']] = 1;
			}
			if(isset($ret[$val['rmt_direction']]['es'][$val['es_condition']])){
				$ret[$val['rmt_direction']]['es'][$val['es_condition']]++;
			}else{
				$ret[$val['rmt_direction']]['es'][$val['es_condition']] = 1;
			}
		}
		return $ret;
	}

	function getMLPData($date, $lane, $minChg, $maxChg){
		$ret = array();

		$field = ($lane == 'Fast') ? 'fast' : 'slow';
		$mlpCondData = $this->db->fetchAll("
		select 
		mlp_direction, 
		case when mlp_".$field."_all_cracks < 5.1 then 'Good' when mlp_".$field."_all_cracks <= 10.1 then 'Fair' when mlp_".$field."_all_cracks <= 15.1 then 'Poor' else 'Bad' end as crack_condition,
		case when mlp_".$field."_roughness < 2.5 then 'Good' when mlp_".$field."_roughness <= 3.5 then 'Fair' when mlp_".$field."_roughness <= 4.5 then 'Poor' else 'Bad' end as roughness_condition,
		case when mlp_".$field."_rutting < 10 then 'Good' when mlp_".$field."_rutting <= 15 then 'Fair' when mlp_".$field."_rutting <= 25 then 'Poor' else 'Bad' end as rutting_condition
		from asset_analysis_mlp where mlp_data_date = :0 and CONVERT (float, mlp_start_chg) >= :1 and CONVERT (float, mlp_end_chg) <= :2 and mlp_package_id=:3", array($date, $minChg, $maxChg, $this->projectID));

		foreach ($mlpCondData as $val) {
			if(isset($ret[$val['mlp_direction']]['crack'][$val['crack_condition']])){
				$ret[$val['mlp_direction']]['crack'][$val['crack_condition']]++;
			}else{
				$ret[$val['mlp_direction']]['crack'][$val['crack_condition']] = 1;
			}
			if(isset($ret[$val['mlp_direction']]['roughness'][$val['roughness_condition']])){
				$ret[$val['mlp_direction']]['roughness'][$val['roughness_condition']]++;
			}else{
				$ret[$val['mlp_direction']]['roughness'][$val['roughness_condition']] = 1;
			}
			if(isset($ret[$val['mlp_direction']]['rutting'][$val['rutting_condition']])){
				$ret[$val['mlp_direction']]['rutting'][$val['rutting_condition']]++;
			}else{
				$ret[$val['mlp_direction']]['rutting'][$val['rutting_condition']] = 1;
			}
		}
		return $ret;
	}

	function getAssetAnalysisDateOpts (){
		$ret = $this->db->fetchCol("select distinct(dateOpts) from ( 
			select distinct (fwd_data_date) as dateOpts from asset_analysis_fwd fwd where fwd_package_id =:0
			union
			select distinct (rmt_data_date) as dateOpts from asset_analysis_rmt rmt where rmt_package_id =:1
			union
			select distinct (mlp_data_date) as dateOpts from asset_analysis_mlp mlp where mlp_package_id =:2) aa order by dateOpts desc", array($this->projectID, $this->projectID, $this->projectID));
		return $ret;
	}

	function getAssetAnalysisChgOpts (){
		$ret = $this->db->fetchCol("select distinct convert(DECIMAL(10, 3), chgOpts) from (
			select distinct (fwd_chainage) as chgOpts from asset_analysis_fwd fwd where fwd_package_id=:0
			union
			select distinct (rmt_chainage) as chgOpts from asset_analysis_rmt rmt where rmt_package_id=:1
			union
			select distinct (mlp.mlp_start_chg) as chgOpts from asset_analysis_mlp mlp where mlp_package_id=:2
			union
			select distinct (mlp2.mlp_end_chg) as chgOpts from asset_analysis_mlp mlp2) aa order by convert(DECIMAL(10, 3), chgOpts) asc", array($this->projectID, $this->projectID, $this->projectID));
		return $ret;
	}

	function getPCAAnalysis($date ='', $lane = '', $minChg='', $maxChg=''){
		// predefined value if not set
		if ($lane == '') $lane = 'Fast';
		if ($minChg == '') $minChg = '0';
		if ($maxChg == '') $maxChg = '999999';

		// get latest date if date is not set
		$cdDate = ($date != '') ? $date : $this->db->fetchOne('select max(fwd_data_date) from asset_analysis_fwd where fwd_package_id = :0', array($this->projectID));
		$rmDate = ($date != '') ? $date : $this->db->fetchOne('select max(rmt_data_date) from asset_analysis_rmt where rmt_package_id=:0', array($this->projectID));
		$mlpDate = ($date != '') ? $date : $this->db->fetchOne('select max(mlp_data_date) from asset_analysis_mlp where mlp_package_id=:0', array($this->projectID));

		return array(
			'cd' => $this->getCDData($cdDate, $lane, $minChg, $maxChg),
			'rm' => $this->getRMData($rmDate, $lane, $minChg, $maxChg),
			'mlp' => $this->getMLPData($mlpDate, $lane, $minChg, $maxChg),
			'dateOpts'=>  $this->getAssetAnalysisDateOpts(),
			'chgOpts'=>  $this->getAssetAnalysisChgOpts(),
			'currDate' => array(
				'cd' => date('d-m-Y',strtotime($cdDate)),
				'rm' => date('d-m-Y',strtotime($rmDate)),
				'mlp' => date('d-m-Y',strtotime($mlpDate)),
			),
		);
	}

	function getNODData(){
		$ret = array();
		$arrLevel = ['1' => "Critical", '2' => "Serious", '3' => "Bad", '4' => "Mild", '5' => "Good"];
		$arrTotal = [];

		if ($this->isWPC) {
			$url = $this->jogetLinkObj->getLink('dash_asset_nod', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);
			if (isset($res['data']) && $res['data']) {
				foreach ($res['data'] as $nod) {
					// based on month and year
					$dateCreated = strtotime($nod['nod_date']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

					$useID = $nod['id'];
					if(!in_array($useID, array_column($arrTotal, 'id')) )
					{
						array_push($arrTotal, [
							'id' => $nod['id'],
							'year' => $year,
							'month' => $month,
						]);
					}

					// total
					$statusUse = isset($arrLevel[$nod['keutamaan']]) ? $arrLevel[$nod['keutamaan']] : 'notFound';
					if($statusUse == 'notFound') continue;

					//table by maintenance category
					$ret['overall']['all']['all']['table'][$statusUse]['raw'][] = $nod;
					$ret['overall'][$year]['all']['table'][$statusUse]['raw'][] = $nod;
					$ret['overall'][$year][$month]['table'][$statusUse]['raw'][] = $nod;

					// total amount by maintenance category
					if (isset($ret['overall']['all']['all']['card']['yearDate']['totalAll'])) {
						$ret['overall']['all']['all']['card']['yearDate']['totalAll'] = $ret['overall']['all']['all']['card']['yearDate']['totalAll'] + (float) $nod['kos_anggaran'];
					}else{
						$ret['overall']['all']['all']['card']['yearDate']['totalAll'] = (float) $nod['kos_anggaran'];
					}
					if (isset($ret['overall'][$year]['all']['card']['yearDate']['totalAll'])) {
						$ret['overall'][$year]['all']['card']['yearDate']['totalAll'] = $ret['overall'][$year]['all']['card']['yearDate']['totalAll'] + (float) $nod['kos_anggaran'];
					}else{
						$ret['overall'][$year]['all']['card']['yearDate']['totalAll'] = (float) $nod['kos_anggaran'];
					}
					if (isset($ret['overall'][$year][$month]['card']['yearDate']['totalAll'])) {
						$ret['overall'][$year][$month]['card']['yearDate']['totalAll'] = $ret['overall'][$year][$month]['card']['yearDate']['totalAll'] + (float) $nod['kos_anggaran'];
					}else{
						$ret['overall'][$year][$month]['card']['yearDate']['totalAll'] = (float) $nod['kos_anggaran'];
					}

					if (isset($ret['overall']['all']['all']['card']['yearDate'][$statusUse])) {
						$ret['overall']['all']['all']['card']['yearDate'][$statusUse] = $ret['overall']['all']['all']['card']['yearDate'][$statusUse] + (float) $nod['kos_anggaran'];
					}else{
						$ret['overall']['all']['all']['card']['yearDate'][$statusUse] = (float) $nod['kos_anggaran'];
					}
					if (isset($ret['overall'][$year]['all']['card']['yearDate'][$statusUse])) {
						$ret['overall'][$year]['all']['card']['yearDate'][$statusUse] = $ret['overall'][$year]['all']['card']['yearDate'][$statusUse] + (float) $nod['kos_anggaran'];
					}else{
						$ret['overall'][$year]['all']['card']['yearDate'][$statusUse] = (float) $nod['kos_anggaran'];
					}
					if (isset($ret['overall'][$year][$month]['card']['yearDate'][$statusUse])) {
						$ret['overall'][$year][$month]['card']['yearDate'][$statusUse] = $ret['overall'][$year][$month]['card']['yearDate'][$statusUse] + (float) $nod['kos_anggaran'];
					}else{
						$ret['overall'][$year][$month]['card']['yearDate'][$statusUse] = (float) $nod['kos_anggaran'];
					}

					// chart quantity status by maintenance category
					if (isset($ret['overall']['all']['all']['chart']['quantityStatus'][$statusUse])) {
						$ret['overall']['all']['all']['chart']['quantityStatus'][$statusUse] ++;
					}else{
						$ret['overall']['all']['all']['chart']['quantityStatus'][$statusUse] = 1;
					}
					if (isset($ret['overall'][$year]['all']['chart']['quantityStatus'][$statusUse])) {
						$ret['overall'][$year]['all']['chart']['quantityStatus'][$statusUse] ++;
					}else{
						$ret['overall'][$year]['all']['chart']['quantityStatus'][$statusUse] = 1;
					}
					if (isset($ret['overall'][$year][$month]['chart']['quantityStatus'][$statusUse])) {
						$ret['overall'][$year][$month]['chart']['quantityStatus'][$statusUse] ++;
					}else{
						$ret['overall'][$year][$month]['chart']['quantityStatus'][$statusUse] = 1;
					}

					// total nod
					if (isset($ret['overall']['all']['all']['card']['quantityStatus']['total'])) {
						$ret['overall']['all']['all']['card']['quantityStatus']['total']++;
					}else{
