	function getWOData(){
		$ret = array();
		if ($this->isWPC) {
			// add back $this->currPackageUuid
			$url = $this->jogetLinkObj->getLink('dash_asset_wo', array($this->currPackageUuid, ''));
			$res = $this->jogetCURL($url);

			if (isset($res['data'])){
				foreach ($res['data'] as $type) {
					// based on month and year
					$dateCreated = strtotime($type['dateCreated']);
					$year = date("Y", $dateCreated);
					$month = date("M", $dateCreated);

						//for wo chart for all
						if (isset($ret['overall']['all']['all']['chart']['all'][$type['asset_catg']])) {
							$ret['overall']['all']['all']['chart']['all'][$type['asset_catg']]++;
						}else{
							$ret['overall']['all']['all']['chart']['all'][$type['asset_catg']] = 1;
						}

						if (isset($ret['overall'][$year]['all']['chart']['all'][$type['asset_catg']])) {
							$ret['overall'][$year]['all']['chart']['all'][$type['asset_catg']]++;
						}else{
							$ret['overall'][$year]['all']['chart']['all'][$type['asset_catg']] = 1;
						}

						if (isset($ret['overall'][$year][$month]['chart']['all'][$type['asset_catg']])) {
							$ret['overall'][$year][$month]['chart']['all'][$type['asset_catg']]++;
						}else{
							$ret['overall'][$year][$month]['chart']['all'][$type['asset_catg']] = 1;
						}

					
						//for wo chart by asset catg
						if (isset($ret['overall']['all']['all']['chart'][$type['asset_catg']][$type['asset_catg']])) {
